 87→async function querySessionIntents(
 88→  surreal: Surreal,
 89→  sessionId: string,
 90→): Promise<readonly AuthorizedIntentSummary[]> {
 91→  const sessionRecord = new RecordId("agent_session", sessionId);
 92→
 93→  const [rows] = await surreal.query<[IntentRow[]]>(
 94→    `SELECT id, authorization_details
 95→     FROM intent
 96→     WHERE id IN (SELECT VALUE in FROM gates WHERE out = $sess)
 97→       AND status = 'authorized';`,
 98→    { sess: sessionRecord },
 99→  );
100→
101→  return (rows ?? []).map((row) => ({
102→    intentId: row.id.id as string,
103→    authorizationDetails: row.authorization_details ?? [],
104→  }));
105→}
