 95→    created_at: row.created_at instanceof Date
 96→      ? row.created_at.toISOString()
 97→      : String(row.created_at),
 98→  };
 99→
100→  if (row.last_status) {
101→    response.last_status = row.last_status;
102→  }
103→  if (row.last_error) {
104→    response.last_error = row.last_error;
105→  }
