125→/**
126→ * Evaluate can_use rate limit (pure function).
127→ */
128→export function evaluateRateLimit(
129→  maxCallsPerHour: number | undefined,
130→  hourlyExecutionCount: number,
131→): GovernanceVerdict {
132→  if (maxCallsPerHour !== undefined && hourlyExecutionCount >= maxCallsPerHour) {
133→    return {
134→      allowed: false,
135→      reason: `Rate limit exceeded: ${hourlyExecutionCount}/${maxCallsPerHour} calls per hour`,
136→      outcome: "rate_limited",
137→    };
138→  }
139→
140→  return { allowed: true };
141→}
