  1→/**
  2→ * Tools Call Handler -- Effect boundary for tools/call dispatch
  3→ *
  4→ * Receives an MCP tool call request, verifies scope against
  5→ * classified tools, forwards authorized calls to upstream MCP,
  6→ * and records trace records for every outcome.
  7→ *
  8→ * Effect boundary: performs IO (upstream MCP calls, SurrealDB trace writes).
  9→ * Pure logic delegated to scope-engine.ts and error-response-builder.ts.
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import type { Surreal } from "surrealdb";
 13→import type { McpClientFactory } from "../tool-registry/mcp-client";
 14→import type { ClassifiedTool } from "./scope-engine";
 15→import { buildIntentRequiredError } from "./error-response-builder";
 16→import { handleCreateIntent } from "./create-intent-handler";
 17→import type { InflightTracker } from "../runtime/types";
 18→import { log } from "../telemetry/logger";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Types
 22→// ---------------------------------------------------------------------------
 23→
 24→export type ToolCallOutcome = "success" | "error" | "intent_required" | "unknown_tool";
 25→
 26→export type ToolCallParams = {
 27→  readonly name: string;
 28→  readonly arguments?: Record<string, unknown>;
 29→};
 30→
 31→export type ToolCallSuccess = {
 32→  readonly kind: "success";
 33→  readonly result: unknown;
 34→};
 35→
 36→export type ToolCallError = {
 37→  readonly kind: "error";
 38→  readonly code: number;
 39→  readonly message: string;
 40→  readonly data?: unknown;
 41→};
 42→
 43→export type ToolCallResult = ToolCallSuccess | ToolCallError;
 44→
 45→export type ToolCallContext = {
 46→  readonly workspaceId: string;
 47→  readonly identityId: string;
 48→  readonly sessionId: string;
 49→};
 50→
 51→export type ToolCallDependencies = {
 52→  readonly surreal: Surreal;
 53→  readonly mcpClientFactory: McpClientFactory;
 54→  readonly inflight: InflightTracker;
 55→};
 56→
 57→// ---------------------------------------------------------------------------
 58→// Trace recording (effect boundary)
 59→// ---------------------------------------------------------------------------
 60→
 61→async function recordToolTrace(
 62→  surreal: Surreal,
 63→  context: ToolCallContext,
 64→  toolName: string,
 65→  outcome: ToolCallOutcome,
 66→  durationMs: number,
 67→  intentId?: string,
 68→  input?: Record<string, unknown>,
 69→  output?: Record<string, unknown>,
 70→): Promise<void> {
 71→  const traceId = crypto.randomUUID();
 72→  const traceRecord = new RecordId("trace", traceId);
 73→
 74→  const content: Record<string, unknown> = {
 75→    type: "tool_call",
 76→    tool_name: toolName,
 77→    outcome,
 78→    workspace: new RecordId("workspace", context.workspaceId),
 79→    actor: new RecordId("identity", context.identityId),
 80→    session: new RecordId("agent_session", context.sessionId),
 81→    duration_ms: Math.round(durationMs),
 82→    created_at: new Date(),
 83→  };
 84→
 85→  if (intentId) {
 86→    content.intent = new RecordId("intent", intentId);
 87→  }
 88→
 89→  if (input) {
 90→    content.input = input;
 91→  }
 92→
 93→  if (output) {
 94→    content.output = output;
 95→  }
 96→
 97→  try {
 98→    await surreal.query(`CREATE $trace CONTENT $content;`, {
 99→      trace: traceRecord,
100→      content,
101→    });
102→
103→    log.info("agent_mcp.tool_trace.captured", "Tool call trace captured", {
104→      trace_id: traceId,
105→      tool_name: toolName,
106→      outcome,
107→      duration_ms: Math.round(durationMs),
108→      workspace_id: context.workspaceId,
