  1→/**
  2→ * Agent MCP Route -- Effect boundary for /mcp/agent/:sessionId
  3→ *
  4→ * Handles JSON-RPC requests from sandbox coding agents. Parses the
  5→ * JSON-RPC envelope, resolves auth context, and dispatches to
  6→ * method-specific handlers.
  7→ *
  8→ * Effect boundary: this module performs IO (DB queries, request parsing).
  9→ * Pure logic lives in scope-engine.ts, tools-list-handler.ts, and
 10→ * error-response-builder.ts.
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { ServerDependencies } from "../runtime/types";
 14→import { HttpError } from "../http/errors";
 15→import { jsonResponse } from "../http/response";
 16→import { resolveAgentSession, type AgentSessionContext } from "./agent-mcp-auth";
 17→import {
 18→  computeEffectiveScope,
 19→  classifyTools,
 20→  type AuthorizedIntentSummary,
 21→  type ClassifiedTool,
 22→} from "./scope-engine";
 23→import { buildToolsList, BRAIN_NATIVE_TOOL_NAMES } from "./tools-list-handler";
 24→import { handleToolCall, type ToolCallParams } from "./tools-call-handler";
 25→import { handleCreateIntent } from "./create-intent-handler";
 26→import {
 27→  resolveToolsForIdentity,
 28→  createQueryGrantedTools,
 29→  createToolResolutionCache,
 30→  type ToolResolutionCache,
 31→  type QueryGrantedTools,
 32→} from "../proxy/tool-resolver";
 33→import type { BrainAction } from "../oauth/types";
 34→
 35→// ---------------------------------------------------------------------------
 36→// Types
 37→// ---------------------------------------------------------------------------
 38→
 39→type JsonRpcRequest = {
 40→  readonly jsonrpc: string;
 41→  readonly id: string | number | null;
 42→  readonly method: string;
 43→  readonly params?: Record<string, unknown>;
 44→};
 45→
 46→type JsonRpcResponse = {
 47→  readonly jsonrpc: "2.0";
 48→  readonly id: string | number | null;
 49→  readonly result?: unknown;
 50→  readonly error?: {
 51→    readonly code: number;
 52→    readonly message: string;
 53→    readonly data?: unknown;
 54→  };
 55→};
 56→
 57→type IntentRow = {
 58→  id: RecordId<"intent">;
 59→  authorization_details?: readonly BrainAction[];
 60→};
 61→
 62→// ---------------------------------------------------------------------------
 63→// JSON-RPC helpers (pure)
 64→// ---------------------------------------------------------------------------
 65→
 66→function jsonRpcSuccess(id: string | number | null, result: unknown): JsonRpcResponse {
 67→  return { jsonrpc: "2.0", id, result };
 68→}
 69→
 70→function jsonRpcError(
 71→  id: string | number | null,
 72→  code: number,
 73→  message: string,
 74→  data?: unknown,
 75→): JsonRpcResponse {
 76→  return { jsonrpc: "2.0", id, error: { code, message, ...(data !== undefined ? { data } : {}) } };
 77→}
 78→
 79→// ---------------------------------------------------------------------------
 80→// Query ports (effect boundary)
 81→// ---------------------------------------------------------------------------
 82→
 83→/**
 84→ * Query authorized intents gating a specific agent session.
 85→ * Returns intent summaries with authorization_details for scope computation.
 86→ */
 87→async function querySessionIntents(
 88→  surreal: Surreal,
 89→  sessionId: string,
 90→): Promise<readonly AuthorizedIntentSummary[]> {
 91→  const sessionRecord = new RecordId("agent_session", sessionId);
 92→
 93→  const [rows] = await surreal.query<[IntentRow[]]>(
 94→    `SELECT id, authorization_details
 95→     FROM intent
 96→     WHERE id IN (SELECT VALUE in FROM gates WHERE out = $sess)
 97→       AND status = 'authorized';`,
 98→    { sess: sessionRecord },
 99→  );
100→
101→  return (rows ?? []).map((row) => ({
102→    intentId: row.id.id as string,
103→    authorizationDetails: row.authorization_details ?? [],
104→  }));
105→}
106→
107→// ---------------------------------------------------------------------------
108→// Shared scope computation
109→// ---------------------------------------------------------------------------
110→
