155→/** Get task dependency tree (recursive) */
156→export async function getTaskDependencyTree(input: {
157→  surreal: Surreal;
158→  workspaceRecord: RecordId<"workspace", string>;
159→  taskRecord: RecordId<"task", string>;
160→}): Promise<{
161→  task: { id: string; title: string; status: string };
162→  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
163→  dependents: Array<{ id: string; title: string; status: string }>;
164→  subtasks: Array<{ id: string; title: string; status: string }>;
165→}> {
166→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
167→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
168→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
169→    throw new Error("task is outside the current workspace scope");
170→  }
171→
172→  const query = `
173→    -- Tasks this task depends on
174→    SELECT id, title, status
175→    FROM task
176→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
177→
178→    -- Tasks that depend on this task
179→    SELECT id, title, status
180→    FROM task
181→    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
182→
183→    -- Subtasks
184→    SELECT id, title, status, created_at
185→    FROM task
186→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
187→    ORDER BY created_at ASC;
188→  `;
189→
190→  const results = await input.surreal
191→    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
192→    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
193→
194→  const [deps, dependents, subtasks] = results;
195→
196→  return {
197→    task: { id: toRawId(task.id), title: task.title, status: task.status },
198→    dependencies: deps.map((d) => ({
199→      id: toRawId(d.id),
200→      title: d.title,
201→      status: d.status,
202→      resolved: d.status === "done" || d.status === "completed",
203→    })),
204→    dependents: dependents.map((d) => ({ id: toRawId(d.id), title: d.title, status: d.status })),
205→    subtasks: subtasks.map((s) => ({ id: toRawId(s.id), title: s.title, status: s.status })),
206→  };
207→}
