458→/**
459→ * Batch-update multiple tasks to "done" in a single transaction,
460→ * then compute parent rollup for any affected parents.
461→ */
462→export async function batchCompleteTasksInTransaction(input: {
463→  surreal: Surreal;
464→  workspaceRecord: RecordId<"workspace", string>;
465→  taskIds: string[];
466→}): Promise<Array<{ task_id: string; status: string; updated: boolean }>> {
467→  if (input.taskIds.length === 0) return [];
468→
469→  const taskRecords = input.taskIds.map((id) => new RecordId("task", id));
470→
471→  // Single transaction: verify ownership + update all tasks + collect parents
472→  const query = `
473→    BEGIN TRANSACTION;
474→
475→    -- Update all matching tasks in this workspace to done.
476→    -- Compare workspace directly as record<workspace> (workspace.id matching does not work reliably).
477→    UPDATE task
478→      SET status = 'done', updated_at = time::now()
479→      WHERE id IN $tasks AND workspace = $workspace
480→      RETURN AFTER;
481→
482→    -- Collect parent records for rollup (dedupe in app layer).
483→    SELECT VALUE out FROM subtask_of WHERE \`in\` IN $tasks;
484→
485→    COMMIT TRANSACTION;
486→  `;
487→
488→  const result = await input.surreal.query<[
489→    null,
490→    Array<{ id: RecordId<"task", string>; status: string }>,
491→    Array<RecordId<"task", string>>,
492→    null,
493→  ]>(query, { tasks: taskRecords, workspace: input.workspaceRecord });
494→
495→  // BEGIN/COMMIT emit null outputs, so update rows are at index 1.
496→  const updatedRows = result[1] ?? [];
497→  const updatedIds = new Set(updatedRows.map((r) => r.id.id as string));
498→
499→  const parentRows = result[2] ?? [];
500→  const parentIds = Array.from(
501→    new Map(parentRows.map((parent) => [parent.id as string, parent])).values(),
502→  );
503→  await Promise.all(parentIds.map((parent) => computeSubtaskRollup(input.surreal, parent)));
504→
505→  return input.taskIds.map((id) => ({
506→    task_id: id,
507→    status: "done",
508→    updated: updatedIds.has(id),
509→  }));
510→}
