512→/** Compute and apply subtask rollup on a parent task */
513→async function computeSubtaskRollup(
514→  surreal: Surreal,
515→  parentRecord: RecordId<"task", string>,
516→): Promise<string> {
517→  const [subtaskRows] = await surreal
518→    .query<[SubtaskRow[]]>(
519→      `SELECT id, title, status
520→       FROM task
521→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
522→      { parent: parentRecord },
523→    )
524→    .collect<[SubtaskRow[]]>();
525→
526→  if (subtaskRows.length === 0) return "unknown";
527→
528→  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
529→  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
530→  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
531→  const allTodo = subtaskRows.every((s) => s.status === "todo");
532→
533→  let derivedStatus: string;
534→
535→  if (allCompleted) derivedStatus = "completed";
536→  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
537→  else if (anyBlocked) derivedStatus = "blocked";
538→  else if (anyInProgress) derivedStatus = "in_progress";
539→  else if (allTodo) derivedStatus = "todo";
540→  else derivedStatus = "in_progress";
541→
542→  await surreal.update(parentRecord).merge({
543→    status: derivedStatus,
544→    updated_at: new Date(),
545→  });
546→
547→  return derivedStatus;
548→}
