585→  taskId?: string;
586→}): Promise<{ session_id: string }> {
587→  const now = new Date();
588→  const sessionRecord = new RecordId("agent_session", randomUUID());
589→
590→  await input.surreal.create(sessionRecord).content({
591→    agent: input.agent,
592→    started_at: now,
593→    workspace: input.workspaceRecord,
594→    created_at: now,
595→    ...(input.projectRecord ? { project: input.projectRecord } : {}),
596→    ...(input.taskId ? { task_id: new RecordId("task", requireRawId(input.taskId, "task_id")) } : {}),
597→  });
598→
599→  // If task-scoped, link session to task (status is managed by explicit transitions, not session creation)
600→  if (input.taskId) {
601→    const taskRecord = new RecordId("task", requireRawId(input.taskId, "task_id"));
602→    const task = await input.surreal.select<TaskRow>(taskRecord);
603→    if (!task) {
604→      throw new Error(`task not found: ${input.taskId}`);
605→    }
606→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
607→      throw new Error("task is outside the current workspace scope");
608→    }
609→    await input.surreal.update(taskRecord).merge({
610→      source_session: sessionRecord,
611→      updated_at: now,
612→    });
613→  }
614→
615→  return { session_id: toRawId(sessionRecord) };
616→}
