708→/** Log a git commit to the graph */
709→export async function logCommit(input: {
710→  surreal: Surreal;
711→  workspaceRecord: RecordId<"workspace", string>;
712→  projectRecord?: RecordId<"project", string>;
713→  sha: string;
714→  message: string;
715→  author: string;
716→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
717→  relatedTaskIds?: string[];
718→  decisionsDetected?: Array<{ name: string; rationale: string }>;
719→}): Promise<{ commit_id: string; tasks_updated: number; tasks_linked: number; decisions_created: number }> {
720→  const now = new Date();
721→  const commitRecord = new RecordId("git_commit", randomUUID());
722→
723→  await input.surreal.create(commitRecord).content({
724→    sha: input.sha,
725→    message: input.message,
726→    author_name: input.author,
727→    workspace: input.workspaceRecord,
728→    authored_at: now,
729→    created_at: now,
730→  });
731→
732→  // Update task statuses
733→  let tasksUpdated = 0;
734→  if (input.taskUpdates?.length) {
735→    for (const update of input.taskUpdates) {
736→      const taskRecord = new RecordId("task", requireRawId(update.task_id, "task_updates[].task_id"));
737→      const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
738→      if (!task) {
739→        throw new Error(`task not found: ${update.task_id}`);
740→      }
741→      if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
742→        throw new Error("task update is outside the current workspace scope");
743→      }
744→      await input.surreal.update(taskRecord).merge({
745→        status: update.new_status,
746→        updated_at: now,
747→      });
748→      tasksUpdated++;
749→    }
750→  }
751→
752→  // Link related tasks to this commit
753→  const linkedTaskIds = new Set<string>();
754→  // Include tasks from task_updates
755→  if (input.taskUpdates?.length) {
756→    for (const update of input.taskUpdates) {
757→      linkedTaskIds.add(requireRawId(update.task_id, "task_updates[].task_id"));
758→    }
759→  }
760→  // Include explicitly declared related tasks
761→  if (input.relatedTaskIds?.length) {
762→    for (const taskId of input.relatedTaskIds) {
763→      linkedTaskIds.add(requireRawId(taskId, "related_task_ids[]"));
764→    }
765→  }
766→  for (const taskId of linkedTaskIds) {
767→    const taskRecord = new RecordId("task", taskId);
768→    const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
769→    if (!task) {
770→      throw new Error(`task not found: ${taskId}`);
771→    }
772→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
773→      throw new Error("task link is outside the current workspace scope");
774→    }
775→    await input.surreal
776→      .relate(taskRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
777→        commit_sha: input.sha,
778→        linked_at: now,
779→      })
780→      .output("after");
781→  }
782→
783→  // Create provisional decisions if flagged
784→  let decisionsCreated = 0;
785→  if (input.decisionsDetected?.length) {
786→    for (const decision of input.decisionsDetected) {
787→      const decisionRecord = new RecordId("decision", randomUUID());
788→      await input.surreal.create(decisionRecord).content({
789→        summary: decision.name,
790→        rationale: decision.rationale,
791→        status: "provisional",
792→        decided_by_name: "code-agent",
793→        workspace: input.workspaceRecord,
794→        source_commit: commitRecord,
795→        created_at: now,
796→        updated_at: now,
797→      });
798→
799→      // Link decision to project (if known)
800→      if (input.projectRecord) {
801→        await input.surreal
802→          .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
803→            added_at: now,
804→          })
805→          .output("after");
806→      }
807→
808→      // Create implemented_by edge
809→      await input.surreal
810→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
811→          commit_sha: input.sha,
812→          linked_at: now,
813→        })
814→        .output("after");
815→
816→      decisionsCreated++;
817→    }
818→  }
819→
820→  return {
821→    commit_id: toRawId(commitRecord),
822→    tasks_updated: tasksUpdated,
823→    tasks_linked: linkedTaskIds.size,
824→    decisions_created: decisionsCreated,
825→  };
826→}
