869→/** Get simple project context for plugin tools. Returns undefined if project not found or outside workspace. */
870→export async function getPluginProjectContext(input: {
871→  surreal: Surreal;
872→  workspaceRecord: RecordId<"workspace", string>;
873→  projectRecord: RecordId<"project", string>;
874→}): Promise<PluginProjectContext | undefined> {
