880→  const [taskCountRows] = await input.surreal
881→    .query<[Array<{ count: number }>]>(
882→      `SELECT count() FROM task WHERE id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project) GROUP ALL;`,
883→      { project: input.projectRecord },
884→    )
885→    .collect<[Array<{ count: number }>]>();
886→
887→  const [featureCountRows] = await input.surreal
888→    .query<[Array<{ count: number }>]>(
889→      `SELECT count() FROM feature WHERE id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project) GROUP ALL;`,
890→      { project: input.projectRecord },
891→    )
892→    .collect<[Array<{ count: number }>]>();
893→
894→  const counts = {
895→    task_count: taskCountRows[0]?.count ?? 0,
896→    feature_count: featureCountRows[0]?.count ?? 0,
897→  };
898→
899→  return {
900→    name: project.name,
901→    status: project.status,
902→    ...(project.description ? { description: project.description } : {}),
903→    taskCount: counts?.task_count ?? 0,
904→    featureCount: counts?.feature_count ?? 0,
905→  };
906→}
