909→// Utility
910→// ---------------------------------------------------------------------------
911→
912→function levenshteinSimilarity(a: string, b: string): number {
913→  if (a === b) return 1;
914→  const longer = a.length > b.length ? a : b;
915→  const shorter = a.length > b.length ? b : a;
916→  if (longer.length === 0) return 1;
917→
918→  const costs: number[] = [];
919→  for (let i = 0; i <= longer.length; i++) {
920→    let lastValue = i;
921→    for (let j = 0; j <= shorter.length; j++) {
922→      if (i === 0) {
923→        costs[j] = j;
924→      } else if (j > 0) {
925→        let newValue = costs[j - 1];
926→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
927→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
928→        }
929→        costs[j - 1] = lastValue;
930→        lastValue = newValue;
931→      }
932→    }
933→    if (i > 0) costs[shorter.length] = lastValue;
934→  }
935→
936→  return (longer.length - costs[shorter.length]) / longer.length;
937→}
