14→/** Core search logic — shared by AI SDK tool wrapper and proxy handler. */
15→export async function executeSearchEntities(
16→  surreal: Surreal,
17→  workspaceRecord: RecordId<"workspace", string>,
18→  input: { query: string; kinds?: SearchEntityKind[]; limit: number },
19→) {
20→  const results = await searchEntitiesByBm25({
21→    surreal,
22→    workspaceRecord,
23→    query: input.query,
24→    ...(input.kinds ? { kinds: input.kinds } : {}),
25→    limit: input.limit,
26→  });
27→
28→  const enriched = await Promise.all(
29→    results.map(async (row) => {
30→      const entityRecord = parseRecordIdString(row.id, [row.kind as GraphEntityTable], row.kind as GraphEntityTable);
31→      const neighbors = await listEntityNeighbors({
32→        surreal,
33→        workspaceRecord,
34→        entityRecord,
35→        limit: 8,
36→      });
37→
38→      return {
39→        id: `${row.kind}:${row.id}`,
40→        kind: row.kind,
41→        name: row.name,
42→        confidence: Number(row.score.toFixed(4)),
43→        ...(row.status ? { status: row.status } : {}),
44→        related: neighbors.slice(0, 4).map((neighbor) => ({
45→          id: `${neighbor.kind}:${neighbor.id}`,
46→          kind: neighbor.kind,
47→          name: neighbor.name,
48→          relation: neighbor.relationKind,
49→        })),
50→      };
51→    }),
52→  );
53→
54→  return { query: input.query, results: enriched };
55→}
