155→async function listFeatures(
156→  surreal: Surreal,
157→  workspaceRecord: RecordId<"workspace", string>,
158→  projectRecord: RecordId<"project", string> | undefined,
159→  status: string | undefined,
160→  limit: number,
161→) {
162→  const conditions = ["workspace = $workspace"];
163→  const params: Record<string, unknown> = { workspace: workspaceRecord, limit };
164→
165→  if (projectRecord) {
166→    conditions.push("id IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)");
167→    params.project = projectRecord;
168→  }
169→
170→  if (status) {
171→    conditions.push("status = $status");
172→    params.status = status;
173→  }
174→
175→  const query = [
176→    "SELECT id, name, status, created_at",
177→    "FROM feature",
178→    `WHERE ${conditions.join(" AND ")}`,
179→    "ORDER BY created_at DESC",
180→    "LIMIT $limit;",
181→  ].join(" ");
182→
183→  const [rows] = await surreal
184→    .query<[Array<{ id: RecordId<"feature", string>; name: string; status: string; created_at: string | Date }>]>(query, params)
185→    .collect<[Array<{ id: RecordId<"feature", string>; name: string; status: string; created_at: string | Date }>]>();
186→
187→  return {
188→    kind: "feature",
189→    count: rows.length,
190→    entities: rows.map((f) => ({
191→      id: `feature:${(f.id.id as string)}`,
192→      name: f.name,
193→      status: f.status,
194→    })),
195→  };
196→}
