 12→type RankedMessage = {
 13→  id: string;
 14→  conversationId: string;
 15→  text: string;
 16→  score: number;
 17→};
 18→
 19→export function createGetConversationHistoryTool(deps: ChatToolDeps) {
 20→  return tool({
 21→    description:
 22→      "Search past conversations for discussions about a topic and return relevant message excerpts with linked entities.",
 23→    inputSchema: z.object({
 24→      query: z.string().min(1).describe("Topic to search for"),
 25→      projectId: z.string().optional().describe("Optional project scope filter"),
 26→    }),
 27→    execute: async (input, options) => {
 28→      const context = requireToolContext(options);
 29→
 30→      const trimmed = input.query.trim();
 31→      if (trimmed.length === 0) return { query: input.query, results: [] };
 32→
 33→      const [messageRows] = await deps.surreal
 34→        .query<[Array<{
 35→          id: RecordId<"message", string>;
 36→          conversation: RecordId<"conversation", string>;
 37→          text: string;
 38→          score: number;
 39→        }>]>(
 40→          `SELECT id, conversation, text, search::score(1) AS score
 41→           FROM message
 42→           WHERE text @1@ $query
 43→           AND conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)
 44→           ORDER BY score DESC
 45→           LIMIT 8;`,
 46→          { workspace: context.workspaceRecord, query: trimmed },
 47→        )
 48→        .collect<[Array<{
 49→          id: RecordId<"message", string>;
 50→          conversation: RecordId<"conversation", string>;
 51→          text: string;
 52→          score: number;
 53→        }>]>();
 54→
 55→      const messages: RankedMessage[] = (messageRows ?? []).map((row) => ({
 56→        id: row.id.id as string,
 57→        conversationId: row.conversation.id as string,
 58→        text: row.text,
 59→        score: row.score,
 60→      }));
 61→
 62→      const enrichedMessages = await Promise.all(
 63→        messages.map(async (message) => {
 64→          const messageRecord = parseRecordIdString(message.id, ["message"], "message");
 65→          const [entityRows] = await deps.surreal
 66→            .query<[Array<GraphEntityRecord>]>(
 67→              "SELECT VALUE out FROM extraction_relation WHERE `in` = $message LIMIT 8;",
 68→              { message: messageRecord },
 69→            )
 70→            .collect<[Array<GraphEntityRecord>]>() ;
 71→
 72→          const linkedEntities = await Promise.all(
 73→            entityRows.map(async (entityRecord) => {
 74→              const table = entityRecord.table.name;
 75→              if (
 76→                table !== "workspace" &&
 77→                table !== "project" &&
 78→                table !== "person" &&
 79→                table !== "feature" &&
 80→                table !== "task" &&
 81→                table !== "decision" &&
 82→                table !== "question"
 83→              ) {
 84→                return undefined;
 85→              }
 86→
 87→              const name = await readEntityName(deps.surreal, entityRecord);
 88→              if (!name) {
 89→                return undefined;
 90→              }
 91→
 92→              return {
 93→                id: `${table}:${entityRecord.id as string}`,
 94→                kind: table,
 95→                name,
 96→              };
 97→            }),
 98→          );
 99→
100→          return {
101→            messageId: `message:${message.id}`,
102→            conversationId: `conversation:${message.conversationId}`,
103→            excerpt: message.text.slice(0, 280),
104→            confidence: Number(message.score.toFixed(4)),
105→            linkedEntities: linkedEntities.filter((value) => value !== undefined),
106→          };
107→        }),
108→      );
109→
110→      return {
111→        query: input.query,
112→        results: enrichedMessages,
113→      };
114→    },
115→  });
116→}
