 8→const CONFIRMABLE_STATUSES = new Set(["provisional", "inferred"]);
 9→
10→export function createConfirmDecisionTool(deps: ChatToolDeps) {
11→  return tool({
12→    description:
13→      "Confirm a provisional or inferred decision. ONLY use this when the user explicitly approves a decision in conversation. Never call this without clear user authorization.",
14→    inputSchema: z.object({
15→      decision_id: z.string().min(1).describe("Decision record ID to confirm"),
16→      notes: z.string().optional().describe("Additional user context"),
17→    }),
18→    execute: async (input, options) => {
19→      const { context } = await requireAuthorizedContext(options, "confirm_decision", deps);
20→
21→      if (context.actor !== "chat_agent") {
22→        throw new Error("confirm_decision is only available for chat_agent context");
23→      }
24→
25→      const decisionRecord = toDecisionRecordId(input.decision_id);
26→      const decision = await getDecisionRecordForWorkspace({
27→        surreal: deps.surreal,
28→        workspaceRecord: context.workspaceRecord,
29→        decisionInput: `decision:${decisionRecord.id as string}`,
30→      });
31→
32→      if (!CONFIRMABLE_STATUSES.has(decision.status)) {
33→        throw new Error(`decision is not confirmable from status '${decision.status}'`);
34→      }
35→
36→      const ownerRecord = context.workspaceOwnerRecord
37→        ? context.workspaceOwnerRecord
38→        : await getWorkspaceOwnerRecord({
39→            surreal: deps.surreal,
40→            workspaceRecord: context.workspaceRecord,
41→          });
42→
43→      const confirmedAt = new Date();
44→      await confirmDecisionRecord({
45→        surreal: deps.surreal,
46→        decisionRecord: decision.id,
47→        confirmedAt,
48→        ...(ownerRecord ? { confirmedBy: ownerRecord } : {}),
49→        ...(input.notes ? { notes: input.notes } : {}),
50→      });
51→
52→      return {
53→        decision_id: `decision:${decision.id.id as string}`,
54→        status: "confirmed",
55→        name: decision.summary,
56→      };
57→    },
58→  });
59→}
