 13→import { requireAuthorizedContext } from "../iam/authority";
 14→import type { ChatToolDeps } from "./types";
 15→
 16→const resolveDecisionInputSchema = z.object({
 17→  question: z.string().min(1).describe("The decision question"),
 18→  options: z.array(z.string().min(1)).optional().describe("Known options being considered"),
 19→  context: z
 20→    .object({
 21→      project: z.string().optional(),
 22→      feature: z.string().optional(),
 23→    })
 24→    .optional()
 25→    .describe("Optional project/feature scope for searching decisions"),
 26→});
 27→
 28→export function createResolveDecisionTool(deps: ChatToolDeps) {
 29→  return tool({
 30→    description:
 31→      "Infer an answer to a decision question from graph context. Returns resolved/inferred/unresolved with rationale and sources.",
 32→    inputSchema: resolveDecisionInputSchema,
 33→    execute: async (input, options) => {
 34→      const { context } = await requireAuthorizedContext(options, "create_decision", deps);
 35→
 36→      const projectRecord = input.context?.project
 37→        ? await resolveWorkspaceProjectRecord({
 38→            surreal: deps.surreal,
 39→            workspaceRecord: context.workspaceRecord,
 40→            projectInput: input.context.project,
 41→          })
 42→        : undefined;
 43→
 44→      const featureRecord = input.context?.feature
 45→        ? await resolveWorkspaceFeatureRecord({
 46→            surreal: deps.surreal,
 47→            workspaceRecord: context.workspaceRecord,
 48→            featureInput: input.context.feature,
 49→          })
 50→        : undefined;
 51→
 52→      const candidates = await searchEntitiesByBm25({
 53→        surreal: deps.surreal,
 54→        workspaceRecord: context.workspaceRecord,
 55→        query: input.question,
 56→        kinds: ["decision"],
 57→        limit: 10,
 58→      });
 59→
 60→      const decisionCandidates = candidates.filter((candidate) => candidate.kind === "decision");
 61→      const topDecision = decisionCandidates[0];
 62→
 63→      if (topDecision && topDecision.score >= 0.92) {
 64→        const existingDecision = parseRecordIdString(topDecision.id, ["decision"], "decision");
 65→        const resolvedFrom = await getDecisionPrimarySourceMessage({
 66→          surreal: deps.surreal,
 67→          workspaceRecord: context.workspaceRecord,
 68→          decisionRecord: existingDecision,
 69→        });
 70→
 71→        await createExtractionProvenanceEdge({
 72→          surreal: deps.surreal,
 73→          sourceRecord: context.currentMessageRecord,
 74→          targetRecord: existingDecision,
 75→          now: new Date(),
 76→          confidence: Math.max(topDecision.score, 0.6),
 77→          model: deps.extractionModelId,
 78→          fromText: input.question,
 79→          evidence: context.latestUserText,
 80→          evidenceSourceRecord: context.currentMessageRecord,
 81→          ...(resolvedFrom ? { resolvedFromRecord: resolvedFrom } : {}),
 82→        });
 83→
 84→        return {
 85→          status: "resolved",
 86→          decision: {
 87→            id: `decision:${topDecision.id}`,
 88→            name: topDecision.name,
 89→          },
 90→          confidence: Number(topDecision.score.toFixed(4)),
 91→          sources: [
 92→            {
 93→              id: `decision:${topDecision.id}`,
 94→              name: topDecision.name,
 95→              score: Number(topDecision.score.toFixed(4)),
 96→            },
 97→          ],
 98→        };
 99→      }
100→
101→      if (topDecision && topDecision.score >= 0.78) {
102→        const now = new Date();
103→        const sources = candidates.slice(0, 5);
104→        const basedOn = sources
105→          .map((source) => {
106→            try {
107→              return parseRecordIdString(source.id, [source.kind as "project" | "feature" | "task" | "decision" | "question"], source.kind as any);
108→            } catch {
109→              return undefined;
110→            }
111→          })
112→          .filter((value): value is GraphEntityRecord => value !== undefined);
113→
114→        const decisionRecord = await createDecisionRecord({
115→          surreal: deps.surreal,
116→          summary: input.question,
117→          status: "inferred",
118→          now,
119→          workspaceRecord: context.workspaceRecord,
120→          sourceMessageRecord: context.currentMessageRecord,
121→          rationale: `Inferred from existing graph context with ${sources.length} related entities.`,
122→          ...(input.options && input.options.length > 0 ? { optionsConsidered: input.options } : {}),
123→          ...(basedOn.length > 0 ? { basedOn } : {}),
124→          inferredBy: "chat_agent",
125→          decidedByName: "chat_agent",
126→          ...(projectRecord ? { projectRecord } : {}),
127→          ...(featureRecord ? { featureRecord } : {}),
128→        });
129→
130→        await createExtractionProvenanceEdge({
131→          surreal: deps.surreal,
132→          sourceRecord: context.currentMessageRecord,
133→          targetRecord: decisionRecord,
134→          now,
135→          confidence: Math.max(topDecision.score, 0.6),
136→          model: deps.extractionModelId,
137→          fromText: input.question,
138→          evidence: context.latestUserText,
139→          evidenceSourceRecord: context.currentMessageRecord,
140→        });
141→
142→        return {
143→          status: "inferred",
144→          decision: {
145→            id: `decision:${decisionRecord.id as string}`,
146→            name: input.question,
147→          },
148→          confidence: Number(topDecision.score.toFixed(4)),
149→          rationale: `Top matching decision: ${topDecision.name}. Related context was strong enough to infer a recommendation.`,
150→          sources: sources.map((source) => ({
151→            id: `${source.kind}:${source.id}`,
152→            name: source.name,
153→            score: Number(source.score.toFixed(4)),
154→          })),
155→        };
156→      }
157→
158→      return {
159→        status: "unresolved",
160→        relatedContext: candidates.slice(0, 6).map((source) => ({
161→          id: `${source.kind}:${source.id}`,
162→          kind: source.kind,
163→          name: source.name,
164→          score: Number(source.score.toFixed(4)),
165→        })),
166→        suggestProvisional: true,
167→      };
168→    },
169→  });
170→}
