  2→import { buildWorkspaceOverview, buildProjectContext, buildTaskContext } from "./context-builder";
  3→import { type SearchEntityKind } from "../graph/queries";
  4→import { searchEntitiesByBm25 } from "../graph/bm25-search";
  5→import type { ContextPacket, TaskContextPacket, WorkspaceOverview } from "./types";
  6→import { loadActiveLearnings } from "../learning/loader";
  7→
  8→// ---------------------------------------------------------------------------
  9→// Types
 10→// ---------------------------------------------------------------------------
 11→
 12→export type IntentContextInput = {
 13→  intent: string;
 14→  cwd?: string;
 15→  paths?: string[];
 16→  session_id?: string;
 17→};
 18→
 19→export type LearningContext = {
 20→  text: string;
 21→  learning_type: string;
 22→  priority: string;
 23→  source: string;
 24→};
 25→
 26→export type IntentContextResult =
 27→  | { level: "task"; data: TaskContextPacket; learnings?: LearningContext[] }
 28→  | { level: "project"; data: ContextPacket; learnings?: LearningContext[] }
 29→  | { level: "workspace"; data: WorkspaceOverview; learnings?: LearningContext[] };
 30→
 31→type ProjectRow = {
 32→  id: RecordId<"project", string>;
 33→  name: string;
 34→  status: string;
 35→  description?: string;
 36→};
 37→
 38→// ---------------------------------------------------------------------------
 39→// Resolution
 40→// ---------------------------------------------------------------------------
 41→
 42→export async function resolveIntentContext(input: {
 43→  surreal: Surreal;
 44→  workspaceRecord: RecordId<"workspace", string>;
 45→  workspaceName: string;
 46→  intent: string;
 47→  cwd?: string;
 48→  paths?: string[];
 49→}): Promise<IntentContextResult> {
 50→  const { surreal, workspaceRecord, workspaceName, intent } = input;
 51→
 52→  const contextResult = await resolveContextLevel({
 53→    surreal, workspaceRecord, workspaceName, intent,
 54→    cwd: input.cwd, paths: input.paths,
 55→  });
 56→
 57→  // Load learnings for MCP agent type (no contextEmbedding — precedents excluded)
 58→  const workspaceId = workspaceRecord.id as string;
 59→  const learningsResult = await loadActiveLearnings({
 60→    surreal,
 61→    workspaceId,
 62→    agentType: "mcp",
 63→  });
 64→
 65→  const learnings: LearningContext[] = learningsResult.learnings.map((l) => ({
 66→    text: l.text,
 67→    learning_type: l.learningType,
 68→    priority: l.priority,
 69→    source: l.source,
 70→  }));
 71→
 72→  return {
 73→    ...contextResult,
 74→    ...(learnings.length > 0 ? { learnings } : {}),
 75→  };
 76→}
 77→
 78→/** Resolves intent to the appropriate context level (task/project/workspace) */
 79→async function resolveContextLevel(input: {
 80→  surreal: Surreal;
 81→  workspaceRecord: RecordId<"workspace", string>;
 82→  workspaceName: string;
 83→  intent: string;
 84→  cwd?: string;
 85→  paths?: string[];
 86→}): Promise<{ level: "task"; data: TaskContextPacket } | { level: "project"; data: ContextPacket } | { level: "workspace"; data: WorkspaceOverview }> {
 87→  const { surreal, workspaceRecord, workspaceName, intent } = input;
 88→
 89→  // Step 1: Explicit entity references in intent text
 90→  const explicitTask = extractEntityRef(intent, "task");
 91→  if (explicitTask) {
 92→    try {
 93→      const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId: explicitTask });
 94→      return { level: "task", data };
 95→    } catch {
 96→      // Task not found — fall through to other strategies
 97→    }
 98→  }
 99→
100→  const explicitProject = extractEntityRef(intent, "project");
101→  if (explicitProject) {
102→    try {
103→      const projectRecord = new RecordId("project", explicitProject);
104→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
105→      return { level: "project", data };
106→    } catch {
107→      // Project not found — fall through
108→    }
109→  }
110→
111→  // Step 2: Single-project shortcut
112→  const projects = await listWorkspaceProjects(surreal, workspaceRecord);
113→  if (projects.length === 1) {
114→    const data = await buildProjectContext({
115→      surreal,
116→      workspaceRecord,
117→      workspaceName,
118→      projectRecord: projects[0].id,
119→    });
120→    return { level: "project", data };
121→  }
122→
123→  // Step 3: BM25 search — match intent text against entities
124→  const bm25Results = await searchEntitiesByBm25({
125→    surreal,
126→    workspaceRecord,
127→    query: intent,
128→    limit: 5,
129→  });
130→
131→  if (bm25Results.length > 0) {
132→    const top = bm25Results[0];
133→
134→    if (top.kind === "task") {
135→      const taskId = top.id.includes(":") ? top.id.split(":")[1] : top.id;
136→      try {
137→        const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId });
138→        return { level: "task", data };
139→      } catch {
140→        // Fall through
141→      }
142→    }
143→
144→    // For project/feature matches, or task fallback: resolve to project context
145→    const projectRecord = await resolveProjectFromMatch(surreal, top);
146→    if (projectRecord) {
147→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
148→      return { level: "project", data };
149→    }
150→  }
151→
152→  // Step 4: Path matching — match directory names against project names
153→  const allPaths = [...(input.paths ?? [])];
154→  if (input.cwd) allPaths.push(input.cwd);
155→
156→  if (allPaths.length > 0 && projects.length > 0) {
157→    const matched = matchPathToProject(allPaths, projects);
158→    if (matched) {
159→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord: matched });
160→      return { level: "project", data };
161→    }
162→  }
163→
164→  // Step 5: Fallback — workspace overview
165→  const data = await buildWorkspaceOverview({ surreal, workspaceRecord, workspaceName });
166→  return { level: "workspace", data };
167→}
168→
169→// ---------------------------------------------------------------------------
170→// Helpers
171→// ---------------------------------------------------------------------------
172→
173→/** Extract explicit entity reference like `task:abc123` or `project:def456` from text */
174→function extractEntityRef(text: string, entityType: string): string | undefined {
175→  const pattern = new RegExp(`\\b${entityType}:([a-zA-Z0-9_-]+)`, "i");
176→  const match = text.match(pattern);
177→  return match ? match[1] : undefined;
178→}
179→
180→/** List all projects in a workspace */
181→async function listWorkspaceProjects(
182→  surreal: Surreal,
183→  workspaceRecord: RecordId<"workspace", string>,
184→): Promise<ProjectRow[]> {
185→  const [rows] = await surreal
186→    .query<[ProjectRow[]]>(
187→      `SELECT id, name, status, description FROM project
188→       WHERE id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace);`,
189→      { workspace: workspaceRecord },
190→    )
191→    .collect<[ProjectRow[]]>();
192→  return rows;
193→}
194→
195→/** Resolve a search match to a project RecordId */
196→async function resolveProjectFromMatch(
197→  surreal: Surreal,
198→  match: { id: string; kind: SearchEntityKind },
199→): Promise<RecordId<"project", string> | undefined> {
200→  if (match.kind === "project") {
201→    const rawId = match.id.includes(":") ? match.id.split(":")[1] : match.id;
202→    return new RecordId("project", rawId);
203→  }
204→
205→  // For task/decision/question/suggestion: find project via belongs_to
206→  // For feature: find project via has_feature (reverse)
207→  const rawId = match.id.includes(":") ? match.id.split(":")[1] : match.id;
208→  const table = match.kind;
209→  const entityRecord = new RecordId(table, rawId);
210→
211→  if (match.kind === "feature") {
212→    const [rows] = await surreal
213→      .query<[Array<{ in: RecordId<"project", string> }>]>(
214→        `SELECT \`in\` FROM has_feature WHERE out = $entity LIMIT 1;`,
215→        { entity: entityRecord },
216→      )
217→      .collect<[Array<{ in: RecordId<"project", string> }>]>();
218→    return rows.length > 0 ? rows[0].in : undefined;
219→  }
220→
221→  // task, decision, question, suggestion → belongs_to → project
222→  const [rows] = await surreal
223→    .query<[Array<{ out: RecordId<"project", string> }>]>(
224→      `SELECT out FROM belongs_to WHERE \`in\` = $entity AND record::tb(out) = "project" LIMIT 1;`,
225→      { entity: entityRecord },
226→    )
227→    .collect<[Array<{ out: RecordId<"project", string> }>]>();
228→  return rows.length > 0 ? rows[0].out : undefined;
229→}
230→
231→/** Match directory paths against project names using normalized token overlap */
232→function matchPathToProject(
233→  paths: string[],
234→  projects: ProjectRow[],
235→): RecordId<"project", string> | undefined {
236→  const pathTokens = new Set<string>();
237→  for (const p of paths) {
238→    for (const segment of p.split("/").filter(Boolean)) {
239→      for (const token of segment.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/)) {
240→        if (token.length > 2) pathTokens.add(token);
241→      }
242→    }
243→  }
244→
245→  if (pathTokens.size === 0) return undefined;
246→
247→  let bestProject: ProjectRow | undefined;
248→  let bestOverlap = 0;
249→
250→  for (const project of projects) {
251→    const nameTokens = new Set(
252→      project.name.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/).filter((t) => t.length > 2),
253→    );
254→    let overlap = 0;
255→    for (const token of nameTokens) {
256→      if (pathTokens.has(token)) overlap++;
257→    }
258→    if (overlap > bestOverlap) {
259→      bestOverlap = overlap;
260→      bestProject = project;
261→    }
262→  }
263→
264→  return bestProject ? bestProject.id : undefined;
265→}
