 4→import { searchEntitiesByBm25 } from "../graph/bm25-search";
 5→import { requireToolContext } from "./helpers";
 6→import type { ChatToolDeps } from "./types";
 7→
 8→function normalizeTokens(value: string): Set<string> {
 9→  return new Set(
10→    value
11→      .toLowerCase()
12→      .replace(/[^a-z0-9\s]/g, " ")
13→      .split(/\s+/)
14→      .map((token) => token.trim())
15→      .filter((token) => token.length > 2),
16→  );
17→}
18→
19→function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
20→  for (const value of a) {
21→    if (b.has(value)) return true;
22→  }
23→  return false;
24→}
25→
26→/** Core logic — shared by AI SDK tool wrapper and proxy handler. */
27→export async function executeCheckConstraints(
28→  surreal: Surreal,
29→  workspaceRecord: RecordId<"workspace", string>,
30→  proposedAction: string,
31→) {
32→  const candidates = await searchEntitiesByBm25({
33→    surreal,
34→    workspaceRecord,
35→    query: proposedAction,
36→    kinds: ["decision"],
37→    limit: 14,
38→  });
39→
40→  const actionTokens = normalizeTokens(proposedAction);
41→  const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
42→  const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
43→  const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
44→
45→  for (const candidate of candidates) {
46→    const candidateTokens = normalizeTokens(candidate.name);
47→    const overlap = hasTokenOverlap(actionTokens, candidateTokens);
48→    const status = candidate.status?.toLowerCase();
49→
50→    if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
51→      hardConflicts.push({
52→        id: `${candidate.kind}:${candidate.id}`, name: candidate.name,
53→        score: Number(candidate.score.toFixed(4)), reason: `Decision is marked ${status}.`,
54→      });
55→      continue;
56→    }
57→
58→    if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
59→      supporting.push({
60→        id: `${candidate.kind}:${candidate.id}`, name: candidate.name,
61→        score: Number(candidate.score.toFixed(4)), reason: "High-similarity decision aligns with proposed action.",
62→      });
63→      continue;
64→    }
65→
66→    if (candidate.score >= 0.72) {
67→      softTensions.push({
68→        id: `${candidate.kind}:${candidate.id}`, name: candidate.name,
69→        score: Number(candidate.score.toFixed(4)),
70→        reason: overlap
71→          ? "Related decision/question may require consistency checks."
72→          : "Semantically related context may be affected.",
73→      });
74→    }
75→  }
76→
77→  return { hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 };
78→}
79→
80→export function createCheckConstraintsTool(deps: ChatToolDeps) {
81→  return tool({
82→    description:
83→      "Check if a proposed action conflicts with existing decisions or constraints. Returns hard conflicts, soft tensions, supporting context, and proceed flag.",
84→    inputSchema: z.object({
85→      proposed_action: z.string().min(1).describe("What is being proposed"),
86→      project: z.string().optional().describe("Optional project scope"),
87→    }),
88→    execute: async (input, options) => {
89→      const context = requireToolContext(options);
90→      return executeCheckConstraints(deps.surreal, context.workspaceRecord, input.proposed_action);
91→    },
92→  });
93→}
