149→
150→export function createAgentMcpHandler(deps: ServerDependencies) {

  1→/**
  2→ * Proxy Policy Evaluator — Pre-request policy enforcement
  3→ *
  4→ * Evaluates three policy dimensions before forwarding LLM requests:
  5→ * 1. Model access — agent_type allowed to use requested model
  6→ * 2. Budget enforcement — workspace daily spend within limit
  7→ * 3. Rate limiting — in-memory sliding window per workspace
  8→ *
  9→ * Pure core with effect boundaries at spend queries and observation writes.
 10→ *
 11→ * Port: (ProxyPolicyContext, ProxyPolicyDependencies) -> Promise<ProxyPolicyResult>
 12→ */
 13→
 14→import { RecordId } from "surrealdb";
 15→import type { Surreal } from "surrealdb";
 16→import type { InflightTracker } from "../runtime/types";
 17→import { createObservation } from "../observation/queries";
 18→import { log } from "../telemetry/logger";
 19→import {
 20→  type RateLimiterState,
 21→  checkRateLimit,
 22→} from "./rate-limiter";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type ProxyPolicyContext = {
 29→  readonly workspaceId: string;
 30→  readonly agentType?: string;
 31→  readonly model: string;
 32→};
 33→
 34→export type ProxyPolicyResult =
 35→  | { decision: "allow"; policyIds: string[] }
 36→  | { decision: "deny_model"; status: 403; body: ModelViolationBody }
 37→  | { decision: "deny_budget"; status: 429; body: BudgetExceededBody }
 38→  | { decision: "deny_rate_limit"; status: 429; body: RateLimitBody; retryAfterSeconds: number };
 39→
 40→type ModelViolationBody = {
 41→  error: "policy_violation";
 42→  policy_ref: string;
 43→  policy_description: string;
 44→  model_requested: string;
 45→  model_suggestion: string[];
 46→  remediation: string;
 47→};
 48→
 49→type BudgetExceededBody = {
 50→  error: "budget_exceeded";
 51→  current_spend_usd: number;
 52→  daily_limit_usd: number;
 53→  time_until_reset_seconds: number;
 54→  remediation: string;
 55→};
 56→
 57→type RateLimitBody = {
 58→  error: "rate_limit_exceeded";
 59→  rate_limit_per_minute: number;
 60→  reset_time_unix: number;
 61→  remediation: string;
 62→};
 63→
 64→type PolicyRuleRecord = {
 65→  id: string;
 66→  condition: { field: string; operator: string; value: unknown } | Array<{ field: string; operator: string; value: unknown }>;
 67→  effect: "allow" | "deny";
 68→  priority: number;
 69→};
 70→
 71→type ProxyPolicyRecord = {
 72→  id: RecordId<"policy">;
 73→  title: string;
 74→  description?: string;
 75→  selector: { agent_role?: string };
 76→  rules: PolicyRuleRecord[];
 77→  status: string;
 78→};
 79→
 80→export type SpendCacheEntry = {
 81→  spendUsd: number;
 82→  fetchedAt: number;
 83→};
 84→
 85→export type SpendCache = Map<string, SpendCacheEntry>;
 86→
 87→const SPEND_CACHE_TTL_MS = 10_000; // 10 seconds
 88→
 89→export type ProxyPolicyDependencies = {
 90→  readonly surreal: Surreal;
 91→  readonly inflight: InflightTracker;
 92→  readonly rateLimiterState: RateLimiterState;
 93→  readonly spendCache: SpendCache;
 94→  readonly noPolicyWarnedWorkspaces: Set<string>;
 95→};
 96→
 97→// ---------------------------------------------------------------------------
 98→// Model Access Evaluation (pure)
 99→// ---------------------------------------------------------------------------
100→
101→type ModelCheckResult =
102→  | { allowed: true; policyIds: string[] }
103→  | { allowed: false; policyRef: string; policyDescription: string; allowedModels: string[] };
104→
105→function evaluateModelAccess(
106→  policies: ProxyPolicyRecord[],
107→  context: ProxyPolicyContext,
108→): ModelCheckResult {
109→  // Filter policies relevant to this agent_type via selector.agent_role
110→  if (!context.agentType) {
111→    // No agent type: policies exist but cannot be matched — allow with warning
112→    log.warn("proxy.policy.missing_agent_type", "Request lacks agent type; model access policies not enforced", {
113→      model: context.model,
114→      workspace_id: context.workspaceId,
115→    });
116→    return { allowed: true, policyIds: policies.map((p) => p.id.id as string) };
117→  }
118→
119→  const relevantPolicies = policies.filter(
120→    (p) => p.selector.agent_role === context.agentType,
121→  );
122→
123→  if (relevantPolicies.length === 0) {
124→    // No agent-specific policies; collect all policy IDs for audit
125→    return { allowed: true, policyIds: policies.map((p) => p.id.id as string) };
126→  }
127→
128→  // Check each relevant policy's rules for model access deny
129→  for (const policy of relevantPolicies) {
130→    for (const rule of policy.rules) {
131→      const conditions = Array.isArray(rule.condition) ? rule.condition : [rule.condition];
132→
133→      for (const cond of conditions) {
134→        // Match deny rules where the model is not in the allowed list
135→        if (
136→          rule.effect === "deny" &&
137→          cond.field === "model" &&
138→          cond.operator === "not_in" &&
139→          Array.isArray(cond.value)
140→        ) {
141→          const allowedModels = cond.value as string[];
142→          if (!allowedModels.includes(context.model)) {
143→            return {
144→              allowed: false,
145→              policyRef: policy.id.id as string,
146→              policyDescription: policy.description ?? policy.title,
147→              allowedModels,
148→            };
149→          }
150→        }
151→      }
152→    }
153→  }
154→
155→  return {
156→    allowed: true,
157→    policyIds: relevantPolicies.map((p) => p.id.id as string),
158→  };
159→}
160→
161→// ---------------------------------------------------------------------------
162→// Budget Check (effect boundary: DB query with cache)
163→// ---------------------------------------------------------------------------
164→
165→function secondsUntilMidnightUtc(now: Date): number {
166→  const tomorrow = new Date(now);
167→  tomorrow.setUTCDate(tomorrow.getUTCDate() + 1);
168→  tomorrow.setUTCHours(0, 0, 0, 0);
169→  return Math.ceil((tomorrow.getTime() - now.getTime()) / 1000);
170→}
171→
172→async function getTodaySpend(
173→  surreal: Surreal,
174→  workspaceId: string,
175→  cache: SpendCache,
176→): Promise<number> {
177→  const now = Date.now();
178→  const cached = cache.get(workspaceId);
179→  if (cached && now - cached.fetchedAt < SPEND_CACHE_TTL_MS) {
180→    return cached.spendUsd;
181→  }
182→
183→  try {
184→    const ws = new RecordId("workspace", workspaceId);
185→    const results = await surreal.query<[Array<{ total: number }>]>(
186→      `SELECT math::sum(cost_usd) AS total FROM trace WHERE workspace = $ws AND created_at >= time::floor(time::now(), 1d) GROUP ALL;`,
187→      { ws },
188→    );
189→    const total = results[0]?.[0]?.total ?? 0;
190→    cache.set(workspaceId, { spendUsd: total, fetchedAt: Date.now() });
191→    return total;
192→  } catch (error) {
193→    log.error("proxy.policy.spend_query_failed", "Failed to query workspace spend", error);
194→    // On query failure, use stale cache if available
195→    if (cached) return cached.spendUsd;
196→    return 0;
197→  }
198→}
199→
200→async function getDailyBudget(
201→  surreal: Surreal,
202→  workspaceId: string,
203→): Promise<number | undefined> {
204→  try {
205→    const ws = new RecordId("workspace", workspaceId);
206→    const results = await surreal.query<[Array<{ daily_budget_usd?: number }>]>(
207→      `SELECT daily_budget_usd FROM $ws;`,
208→      { ws },
209→    );
210→    return results[0]?.[0]?.daily_budget_usd;
211→  } catch {
212→    return undefined;
213→  }
214→}
215→
216→// ---------------------------------------------------------------------------
217→// Load workspace policies (effect boundary)
218→// ---------------------------------------------------------------------------
219→
220→async function loadWorkspacePolicies(
221→  surreal: Surreal,
222→  workspaceId: string,
223→): Promise<ProxyPolicyRecord[]> {
224→  try {
225→    const ws = new RecordId("workspace", workspaceId);
226→    const results = await surreal.query<[ProxyPolicyRecord[]]>(
227→      `SELECT * FROM policy WHERE workspace = $ws AND status = 'active';`,
228→      { ws },
229→    );
230→    return results[0] ?? [];
231→  } catch (error) {
232→    log.error("proxy.policy.load_failed", "Failed to load workspace policies", error);
233→    return [];
234→  }
235→}
