 14→const editableWorkItemTableSchema = z.enum(["task", "feature", "project"]);
 15→
 16→export function createEditWorkItemTool(deps: ChatToolDeps) {
 17→  return tool({
 18→    description:
 19→      "Edit an existing task/feature/project by id. Use for rename or metadata updates. Do NOT use this to create new entities.",
 20→    inputSchema: z.object({
 21→      id: z.string().min(1).describe("Existing work item id in table:id format (task:..., feature:..., project:...)"),
 22→      title: z.string().min(1).optional().describe("New title/name"),
 23→      status: z.string().min(1).optional().describe("Optional new status"),
 24→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional category (task/feature only)"),
 25→      priority: z.enum(ENTITY_PRIORITIES).optional().describe("Optional priority (task only)"),
 26→      rationale: z.string().min(1).optional().describe("Optional rationale note appended as a description entry"),
 27→    }),
 28→    execute: async (input, options) => {
 29→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 30→      const now = new Date();
 31→      const workItemRecord = parseRecordIdString(input.id, ["task", "feature", "project"]);
 32→
 33→      const inWorkspace = await isEntityInWorkspace(
 34→        deps.surreal,
 35→        context.workspaceRecord,
 36→        workItemRecord,
 37→      );
 38→      if (!inWorkspace) {
 39→        throw new Error(`work item is not in workspace: ${input.id}`);
 40→      }
 41→
 42→      const tableName = editableWorkItemTableSchema.parse(workItemRecord.table.name);
 43→      const patch: Record<string, unknown> = { updated_at: now };
 44→      const updatedFields: string[] = [];
 45→
 46→      if (input.title) {
 47→        if (tableName === "task") {
 48→          patch.title = input.title;
 49→        } else {
 50→          patch.name = input.title;
 51→        }
 52→        updatedFields.push("title");
 53→      }
 54→
 55→      if (input.status) {
 56→        patch.status = input.status;
 57→        updatedFields.push("status");
 58→      }
 59→
 60→      if (input.category) {
 61→        if (tableName === "project") {
 62→          throw new Error("category is not editable on project");
 63→        }
 64→        patch.category = input.category;
 65→        updatedFields.push("category");
 66→      }
 67→
 68→      if (input.priority) {
 69→        if (tableName !== "task") {
 70→          throw new Error("priority is only editable on task");
 71→        }
 72→        patch.priority = input.priority;
 73→        updatedFields.push("priority");
 74→      }
 75→
 76→      if (updatedFields.length === 0 && !input.rationale) {
 77→        throw new Error("at least one editable field must be provided");
 78→      }
 79→
 80→      if (updatedFields.length > 0) {
 81→        await deps.surreal.update(workItemRecord).merge(patch);
 82→      }
 83→
 84→      if (input.rationale) {
 85→        await seedDescriptionEntry({
 86→          surreal: deps.surreal,
 87→          targetRecord: workItemRecord,
 88→          text: input.rationale,
 89→        });
 90→      }
 91→
 92→      await createExtractionProvenanceEdge({
 93→        surreal: deps.surreal,
 94→        sourceRecord: context.currentMessageRecord,
 95→        targetRecord: workItemRecord,
 96→        now,
 97→        confidence: 0.95,
 98→        model: deps.extractionModelId,
 99→        fromText: input.title ?? input.id,
100→        evidence: context.latestUserText,
101→        evidenceSourceRecord: context.currentMessageRecord,
102→      });
103→
104→      const updatedName = await readEntityName(deps.surreal, workItemRecord);
105→
106→      return {
107→        entity_id: `${tableName}:${workItemRecord.id as string}`,
108→        kind: tableName,
109→        title: updatedName ?? input.title ?? input.id,
110→        updated_fields: updatedFields,
111→        ...(input.rationale ? { rationale_added: true } : {}),
112→      };
113→    },
114→  });
115→}
