  4→import { searchEntitiesByBm25 } from "../graph/bm25-search";
  5→import { requireAuthorizedContext } from "../iam/authority";
  6→import type { ChatToolDeps } from "./types";
  7→
  8→type SuggestedWorkItem = {
  9→  kind: "task" | "feature" | "project";
 10→  title: string;
 11→  rationale: string;
 12→  category?: EntityCategory;
 13→  project?: string;
 14→  priority?: string;
 15→  possible_duplicate?: {
 16→    id: string;
 17→    name: string;
 18→    similarity: number;
 19→  };
 20→};
 21→
 22→type UpdatedWorkItem = {
 23→  existing_id: string;
 24→  title: string;
 25→  changes: string;
 26→};
 27→
 28→type DiscardedWorkItem = {
 29→  title: string;
 30→  reason: string;
 31→};
 32→
 33→const CLOSED_STATUSES = new Set(["done", "completed", "closed", "resolved", "superseded"]);
 34→
 35→export function createSuggestWorkItemsTool(deps: ChatToolDeps) {
 36→  return tool({
 37→    description:
 38→      "Process a batch of proposed work items and return issue-style PM triage buckets: suggestions, updated, discarded.",
 39→    inputSchema: z.object({
 40→      items: z.array(
 41→        z.object({
 42→          kind: z.enum(["task", "feature", "project"]).describe("project: named product area (MUST exist before features/tasks). feature: capability within an existing project. task: concrete executable work."),
 43→          title: z.string().min(1).describe("Concise work item title"),
 44→          rationale: z.string().min(1).describe("Why this work item is needed"),
 45→          category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional work item category"),
 46→          project: z.string().optional().describe("Optional project scope"),
 47→          priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important. medium: normal. low: nice-to-have."),
 48→        }),
 49→      ).min(1).max(25),
 50→    }),
 51→    execute: async (input, options) => {
 52→      const { context } = await requireAuthorizedContext(options, "create_suggestion", deps);
 53→      const suggestions: SuggestedWorkItem[] = [];
 54→      const updated: UpdatedWorkItem[] = [];
 55→      const discarded: DiscardedWorkItem[] = [];
 56→
 57→      for (const item of input.items) {
 58→        const suggestion: SuggestedWorkItem = {
 59→          kind: item.kind,
 60→          title: item.title,
 61→          rationale: item.rationale,
 62→          ...(item.category ? { category: item.category } : {}),
 63→          ...(item.project ? { project: item.project } : {}),
 64→          ...(item.priority ? { priority: item.priority } : {}),
 65→        };
 66→
 67→        // BM25 text search for duplicate detection -- replaces embedding similarity
 68→        const candidates = await searchEntitiesByBm25({
 69→          surreal: deps.surreal,
 70→          workspaceRecord: context.workspaceRecord,
 71→          query: item.title,
 72→          kinds: [item.kind],
 73→          limit: 5,
 74→        });
 75→
 76→        const top = candidates[0];
 77→        if (!top) {
 78→          suggestions.push(suggestion);
 79→          continue;
 80→        }
 81→
 82→        const normalizedTopStatus = top.status ? top.status.trim().toLowerCase() : undefined;
 83→        if (normalizedTopStatus && CLOSED_STATUSES.has(normalizedTopStatus)) {
 84→          suggestions.push(suggestion);
 85→          continue;
 86→        }
 87→
 88→        // BM25 duplicate detection: exact title match = discard, partial match = merge
 89→        const normalizedTopName = top.name.trim().toLowerCase();
 90→        const normalizedTitle = item.title.trim().toLowerCase();
 91→
 92→        if (normalizedTopName === normalizedTitle) {
 93→          discarded.push({
 94→            title: item.title,
 95→            reason: `Exact duplicate of existing item ${top.kind}:${top.id} (${top.name})`,
 96→          });
 97→          continue;
 98→        }
 99→
100→        // BM25 match means significant keyword overlap -- suggest merge
101→        updated.push({
102→          existing_id: `${top.kind}:${top.id}`,
103→          title: top.name,
104→          changes: `Merge context from suggested item '${item.title}'`,
105→        });
106→      }
107→
108→      return {
109→        suggestions,
110→        updated,
111→        discarded,
112→      };
113→    },
114→  });
115→}
