 1→/**
 2→ * Tool Injector — Pure Function
 3→ *
 4→ * Merges Brain-managed tool definitions into the LLM request body's tools[].
 5→ * Runtime tools are preserved unmodified; Brain tools are appended after.
 6→ * When a name collision occurs, the runtime version takes precedence (Brain tool skipped).
 7→ *
 8→ * Step 7.5 in the proxy pipeline (between context injection and forwarding).
 9→ */
10→
11→// ---------------------------------------------------------------------------
12→// Types
13→// ---------------------------------------------------------------------------
14→
15→/** Anthropic tool format (the shape expected by the Messages API). */
16→export type AnthropicTool = {
17→  name: string;
18→  description: string;
19→  input_schema: Record<string, unknown>;
20→  output_schema?: Record<string, unknown>;
21→};
22→
23→/** Resolved tool from Brain's can_use graph query (internal, richer than Anthropic format). */
24→export type ResolvedTool = {
25→  name: string;
26→  description: string;
27→  input_schema: Record<string, unknown>;
28→  output_schema?: Record<string, unknown>;
29→  toolkit: string;
30→  risk_level: string;
31→  source_server_id?: string;
32→};
33→
34→// ---------------------------------------------------------------------------
35→// Pure Function: injectTools
36→// ---------------------------------------------------------------------------
37→
38→/**
39→ * Merge Brain-managed tools into the request's tool list.
40→ *
41→ * - Runtime tools are preserved first, unmodified.
42→ * - Brain tools are appended, but only if no runtime tool shares the same name.
43→ * - Output is in Anthropic tool format (name, description, input_schema only).
44→ *
45→ * @param runtimeTools - Tools already in the request body (may be undefined)
46→ * @param resolvedTools - Brain-managed tools resolved from can_use edges
47→ * @returns Merged tool list in Anthropic format
48→ */
49→export function injectTools(
50→  runtimeTools: AnthropicTool[] | undefined,
51→  resolvedTools: ResolvedTool[],
52→): AnthropicTool[] {
53→  const existing = runtimeTools ?? [];
54→
55→  if (resolvedTools.length === 0) {
56→    return [...existing];
57→  }
58→
59→  const runtimeNames = new Set(existing.map((tool) => tool.name));
60→
61→  const brainToolsToInject: AnthropicTool[] = resolvedTools
62→    .filter((tool) => !runtimeNames.has(tool.name))
63→    .map(toAnthropicFormat);
64→
65→  return [...existing, ...brainToolsToInject];
66→}
67→
68→// ---------------------------------------------------------------------------
69→// Internal: Format Conversion
70→// ---------------------------------------------------------------------------
71→
72→/** Strip internal fields (toolkit, risk_level) to produce Anthropic-compatible tool. */
73→function toAnthropicFormat(tool: ResolvedTool): AnthropicTool {
74→  const result: AnthropicTool = {
75→    name: tool.name,
76→    description: tool.description,
77→    input_schema: tool.input_schema,
78→  };
79→  if (tool.output_schema) {
80→    result.output_schema = tool.output_schema;
81→  }
82→  return result;
83→}
