 1→import type { IntentRecord, IntentStatus } from "./types";
 2→
 3→// --- Veto Event Types ---
 4→
 5→export type VetoEvent =
 6→  | { type: "veto_window_opened"; intentId: string; expiresAt: Date }
 7→  | { type: "veto_auto_approved"; intentId: string }
 8→  | { type: "veto_cancelled"; intentId: string };
 9→
10→// --- Dependency Ports ---
11→
12→export type VetoManagerDeps = {
13→  updateStatus: (
14→    intentId: string,
15→    status: IntentStatus,
16→  ) => Promise<{ ok: true; record: IntentRecord } | { ok: false; error: string }>;
17→  emitVetoEvent: (event: VetoEvent) => void;
18→  queryExpiredVetoIntents: () => Promise<IntentRecord[]>;
19→};
20→
21→// --- VetoManager Interface ---
22→
23→export type VetoManager = {
24→  startVetoWindow: (intentId: string, expiresAt: Date, deps: VetoManagerDeps) => void;
25→  cancelVetoWindow: (intentId: string) => void;
26→  recoverExpiredWindows: (deps: VetoManagerDeps) => Promise<void>;
27→  shutdown: () => void;
28→  activeWindowCount: () => number;
29→};
30→
31→// --- Configuration ---
32→
33→type VetoManagerConfig = {
34→  vetoDurationMs?: number;
35→};
36→
37→// --- Factory ---
38→
39→export function createVetoManager(_config?: VetoManagerConfig): VetoManager {
40→  const timers = new Map<string, ReturnType<typeof setTimeout>>();
41→
42→  const autoApprove = async (intentId: string, deps: VetoManagerDeps): Promise<void> => {
43→    timers.delete(intentId);
44→    await deps.updateStatus(intentId, "authorized");
45→    deps.emitVetoEvent({ type: "veto_auto_approved", intentId });
46→  };
47→
48→  return {
49→    startVetoWindow(intentId: string, expiresAt: Date, deps: VetoManagerDeps): void {
50→      const delayMs = Math.max(0, expiresAt.getTime() - Date.now());
51→
52→      const timer = setTimeout(() => {
53→        autoApprove(intentId, deps);
54→      }, delayMs);
55→
56→      timers.set(intentId, timer);
57→
58→      deps.emitVetoEvent({
59→        type: "veto_window_opened",
60→        intentId,
61→        expiresAt,
62→      });
63→    },
64→
65→    cancelVetoWindow(intentId: string): void {
66→      const timer = timers.get(intentId);
67→      if (timer) {
68→        clearTimeout(timer);
69→        timers.delete(intentId);
70→      }
71→    },
72→
73→    async recoverExpiredWindows(deps: VetoManagerDeps): Promise<void> {
74→      const expired = await deps.queryExpiredVetoIntents();
75→      for (const intent of expired) {
76→        const intentId = intent.id.id as string;
77→        await autoApprove(intentId, deps);
78→      }
79→    },
80→
81→    shutdown(): void {
82→      for (const timer of timers.values()) {
83→        clearTimeout(timer);
84→      }
85→      timers.clear();
86→    },
87→
88→    activeWindowCount(): number {
89→      return timers.size;
90→    },
91→  };
92→}
