  4→ * Receives an MCP tool call request, verifies scope against
  5→ * classified tools, forwards authorized calls to upstream MCP,
  6→ * and records trace records for every outcome.
  7→ *
  8→ * Effect boundary: performs IO (upstream MCP calls, SurrealDB trace writes).
  9→ * Pure logic delegated to scope-engine.ts and error-response-builder.ts.
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import type { Surreal } from "surrealdb";
 13→import type { McpClientFactory } from "../tool-registry/mcp-client";
 14→import type { ClassifiedTool } from "./scope-engine";
