 23→
 24→export type ToolCallOutcome = "success" | "error" | "intent_required" | "unknown_tool";
 25→
 26→export type ToolCallParams = {
 27→  readonly name: string;
 28→  readonly arguments?: Record<string, unknown>;
 29→};
 30→
 31→export type ToolCallSuccess = {
 32→  readonly kind: "success";
 33→  readonly result: unknown;
 34→};
 35→
