 57→// ---------------------------------------------------------------------------
 58→// Trace recording (effect boundary)
 59→// ---------------------------------------------------------------------------
 60→
 61→async function recordToolTrace(
 62→  surreal: Surreal,
 63→  context: ToolCallContext,
 64→  toolName: string,
 65→  outcome: ToolCallOutcome,
 66→  durationMs: number,
 67→  intentId?: string,
 68→  input?: Record<string, unknown>,
 69→  output?: Record<string, unknown>,
 70→): Promise<void> {
 71→  const traceId = crypto.randomUUID();
 72→  const traceRecord = new RecordId("trace", traceId);
 73→
 74→  const content: Record<string, unknown> = {
 75→    type: "tool_call",
 76→    tool_name: toolName,
 77→    outcome,
 78→    workspace: new RecordId("workspace", context.workspaceId),
 79→    actor: new RecordId("identity", context.identityId),
 80→    session: new RecordId("agent_session", context.sessionId),
 81→    duration_ms: Math.round(durationMs),
 82→    created_at: new Date(),
 83→  };
 84→
 85→  if (intentId) {
 86→    content.intent = new RecordId("intent", intentId);
 87→  }
 88→
 89→  if (input) {
 90→    content.input = input;
 91→  }
 92→
 93→  if (output) {
 94→    content.output = output;
 95→  }
 96→
 97→  try {
 98→    await surreal.query(`CREATE $trace CONTENT $content;`, {
 99→      trace: traceRecord,
100→      content,
101→    });
102→
103→    log.info("agent_mcp.tool_trace.captured", "Tool call trace captured", {
104→      trace_id: traceId,
105→      tool_name: toolName,
106→      outcome,
107→      duration_ms: Math.round(durationMs),
108→      workspace_id: context.workspaceId,
109→    });
110→  } catch (error) {
111→    log.error("agent_mcp.tool_trace.write_failed", "Failed to write tool trace", error);
112→  }
113→}
114→
115→// ---------------------------------------------------------------------------
116→// Upstream forwarding (effect boundary)
117→// ---------------------------------------------------------------------------
118→
119→async function forwardToUpstream(
120→  mcpClientFactory: McpClientFactory,
121→  serverUrl: string,
122→  toolName: string,
123→  toolArgs: Record<string, unknown>,
124→): Promise<unknown> {
125→  // The mcpClientFactory may be a real factory or a test mock (cast as never).
126→  // Real factory: connect() returns McpConnectionResult with .client, separate callTool/disconnect.
127→  // Test mock: connect() returns {callTool(name, args), close()} directly.
128→  // We handle both patterns via duck-typing since the mock is cast as `never`.
129→  const connection = await mcpClientFactory.connect(serverUrl, "streamable-http");
130→
131→  try {
132→    if (typeof mcpClientFactory.callTool === "function") {
133→      // Real McpClientFactory: use factory methods with the client object
134→      const result = await mcpClientFactory.callTool(
135→        (connection as { client: unknown }).client as never,
136→        toolName,
137→        toolArgs,
138→      );
139→      return result;
140→    }
141→    // Mock/simplified path: connection itself has callTool
142→    return await (connection as unknown as { callTool: (name: string, args: Record<string, unknown>) => Promise<unknown> }).callTool(
143→      toolName,
144→      toolArgs,
145→    );
146→  } finally {
147→    if (typeof mcpClientFactory.disconnect === "function") {
148→      await mcpClientFactory.disconnect(
149→        (connection as { client: unknown }).client as never,
150→      ).catch(() => {});
151→    } else if (typeof (connection as unknown as { close?: () => Promise<void> }).close === "function") {
152→      await (connection as unknown as { close: () => Promise<void> }).close().catch(() => {});
153→    }
154→  }
155→}
156→
157→// ---------------------------------------------------------------------------
158→// Tool lookup (pure)
159→// ---------------------------------------------------------------------------
160→
161→function findClassifiedTool(
162→  classifiedTools: readonly ClassifiedTool[],
163→  toolName: string,
164→): ClassifiedTool | undefined {
165→  return classifiedTools.find((ct) => ct.tool.name === toolName);
166→}
167→
168→// ---------------------------------------------------------------------------
169→// Public API
170→// ---------------------------------------------------------------------------
171→
172→/**
173→ * Handle a tools/call JSON-RPC request.
174→ *
175→ * Pipeline:
176→ *   1. Look up tool in classified list
177→ *   2. Branch on classification: authorized -> forward, gated -> 403, brain_native -> 501
178→ *   3. Record trace for ALL outcomes
179→ *   4. Return result or error
180→ */
181→export async function handleToolCall(
182→  params: ToolCallParams,
183→  classifiedTools: readonly ClassifiedTool[],
184→  context: ToolCallContext,
185→  deps: ToolCallDependencies,
186→): Promise<ToolCallResult> {
187→  const startTime = performance.now();
188→  const toolName = params.name;
189→  const toolArgs = params.arguments ?? {};
190→
191→  // 1. Look up the tool
192→  const classified = findClassifiedTool(classifiedTools, toolName);
193→
194→  if (!classified) {
195→    const durationMs = performance.now() - startTime;
196→    deps.inflight.track(
197→      recordToolTrace(deps.surreal, context, toolName, "unknown_tool", durationMs),
198→    );
199→    return {
200→      kind: "error",
201→      code: -32602,
202→      message: "Unknown tool",
203→    };
204→  }
205→
206→  // 2. Branch on classification
207→  switch (classified.classification.kind) {
208→    case "authorized": {
209→      const intentId = classified.classification.matchingIntent.intentId;
210→      try {
211→        // Resolve upstream server URL from source_server_id
212→        const serverUrl = classified.tool.source_server_id
213→          ? await resolveServerUrl(deps.surreal, classified.tool.source_server_id)
214→          : undefined;
215→
216→        const result = await forwardToUpstream(
217→          deps.mcpClientFactory,
218→          serverUrl ?? "unknown",
219→          toolName,
220→          toolArgs,
221→        );
222→
223→        const durationMs = performance.now() - startTime;
224→        deps.inflight.track(
225→          recordToolTrace(
226→            deps.surreal, context, toolName, "success", durationMs, intentId,
227→            toolArgs, { outcome: "success" },
228→          ),
229→        );
230→
231→        return { kind: "success", result };
232→      } catch (error) {
233→        const durationMs = performance.now() - startTime;
234→        const errorMessage = error instanceof Error ? error.message : String(error);
235→        deps.inflight.track(
236→          recordToolTrace(
237→            deps.surreal, context, toolName, "error", durationMs, intentId,
238→            toolArgs, { outcome: "error", error: errorMessage },
239→          ),
240→        );
241→
242→        return {
243→          kind: "error",
244→          code: -32000,
245→          message: `Tool call failed: ${errorMessage}`,
246→        };
247→      }
248→    }
249→
250→    case "gated": {
251→      const durationMs = performance.now() - startTime;
252→      const intentRequiredError = buildIntentRequiredError(
253→        toolName,
254→        classified.tool.toolkit,
255→        classified.tool.input_schema,
256→      );
257→
258→      deps.inflight.track(
259→        recordToolTrace(
260→          deps.surreal, context, toolName, "intent_required", durationMs,
261→          undefined, toolArgs, { outcome: "intent_required" },
262→        ),
263→      );
264→
265→      return {
266→        kind: "error",
267→        code: intentRequiredError.code,
268→        message: intentRequiredError.message,
269→        data: intentRequiredError.data,
270→      };
271→    }
272→
273→    case "brain_native": {
274→      if (toolName === "create_intent") {
275→        const outcome = await handleCreateIntent(toolArgs, context, deps.surreal);
276→        const durationMs = performance.now() - startTime;
277→
278→        if (outcome.status === "authorized") {
279→          deps.inflight.track(
280→            recordToolTrace(
281→              deps.surreal, context, toolName, "success", durationMs,
282→              outcome.intentId, toolArgs, { outcome: "success", intent_id: outcome.intentId },
283→            ),
284→          );
285→          return {
286→            kind: "success",
287→            result: { status: outcome.status, intentId: outcome.intentId },
288→          };
289→        }
290→
291→        if (outcome.status === "pending_veto") {
292→          deps.inflight.track(
293→            recordToolTrace(
294→              deps.surreal, context, toolName, "success", durationMs,
295→              outcome.intentId, toolArgs, { outcome: "pending_veto", intent_id: outcome.intentId },
296→            ),
297→          );
298→          return {
299→            kind: "success",
300→            result: { status: outcome.status, intentId: outcome.intentId },
301→          };
302→        }
303→
304→        if (outcome.status === "vetoed") {
305→          deps.inflight.track(
306→            recordToolTrace(
307→              deps.surreal, context, toolName, "error", durationMs,
308→              undefined, toolArgs, { outcome: "vetoed", reason: outcome.reason },
309→            ),
310→          );
311→          return {
312→            kind: "error",
313→            code: -32000,
314→            message: outcome.reason,
315→          };
316→        }
317→
318→        deps.inflight.track(
319→          recordToolTrace(
320→            deps.surreal, context, toolName, "error", durationMs,
321→            undefined, toolArgs, { outcome: "error", reason: outcome.reason },
322→          ),
323→        );
324→        return {
325→          kind: "error",
326→          code: -32000,
327→          message: outcome.reason,
328→        };
329→      }
330→
331→      // Other brain-native tools (get_context, etc.) not yet implemented
332→      const durationMs = performance.now() - startTime;
333→      deps.inflight.track(
334→        recordToolTrace(deps.surreal, context, toolName, "error", durationMs),
335→      );
336→      return {
337→        kind: "error",
338→        code: -32601,
339→        message: `Not implemented: brain-native tool '${toolName}'`,
340→      };
341→    }
342→  }
343→}
