345→// ---------------------------------------------------------------------------
346→// Server URL resolution (effect boundary)
347→// ---------------------------------------------------------------------------
348→
349→async function resolveServerUrl(
350→  surreal: Surreal,
351→  sourceServerId: string,
352→): Promise<string | undefined> {
353→  const serverRecord = new RecordId("mcp_server", sourceServerId);
354→  const [rows] = await surreal.query<[Array<{ url: string }>]>(
355→    `SELECT url FROM $record;`,
356→    { record: serverRecord },
357→  );
358→  return rows?.[0]?.url;
359→}
