 1→/**
 2→ * Scope Engine — Pure functions for computing effective tool scope
 3→ * from intent authorization details and classifying tools.
 4→ *
 5→ * Pure core: no IO, no DB, no side effects.
 6→ */
 7→import type { BrainAction } from "../oauth/types";
 8→import type { ResolvedTool } from "../proxy/tool-injector";
 9→
10→// ---------------------------------------------------------------------------
11→// Types
12→// ---------------------------------------------------------------------------
13→
14→export type AuthorizedIntentSummary = {
15→  readonly intentId: string;
16→  readonly authorizationDetails: readonly BrainAction[];
17→};
18→
19→export type ToolClassification =
20→  | { readonly kind: "authorized"; readonly matchingIntent: AuthorizedIntentSummary }
21→  | { readonly kind: "gated" }
22→  | { readonly kind: "brain_native" };
23→
24→export type EffectiveScope = {
25→  readonly authorizedActions: readonly BrainAction[];
26→  readonly intents: readonly AuthorizedIntentSummary[];
27→};
28→
29→export type ClassifiedTool = {
30→  readonly tool: ResolvedTool;
31→  readonly classification: ToolClassification;
32→};
33→
34→// ---------------------------------------------------------------------------
35→// Pure functions
36→// ---------------------------------------------------------------------------
37→
38→/** Unions authorization_details from multiple intents into a flat EffectiveScope. */
39→export function computeEffectiveScope(
40→  intents: readonly AuthorizedIntentSummary[],
41→): EffectiveScope {
42→  const authorizedActions = intents.flatMap(
43→    (intent) => intent.authorizationDetails,
44→  );
45→  return { authorizedActions, intents };
46→}
47→
48→/**
49→ * Build the resource string used for matching actions to tools.
50→ * Format: `mcp_tool:{toolkit}:{toolName}`
51→ */
52→function buildToolResource(toolkit: string, toolName: string): string {
53→  return `mcp_tool:${toolkit}:${toolName}`;
54→}
55→
56→/** Find the first intent whose authorization_details contain a matching resource. */
57→function findMatchingIntent(
58→  toolResource: string,
59→  effectiveScope: EffectiveScope,
60→): AuthorizedIntentSummary | undefined {
61→  return effectiveScope.intents.find((intent) =>
62→    intent.authorizationDetails.some(
63→      (action) => action.resource === toolResource,
64→    ),
65→  );
66→}
67→
68→/** Classify a single tool against the effective scope and brain-native set. */
69→function classifyTool(
70→  tool: ResolvedTool,
71→  effectiveScope: EffectiveScope,
72→  brainNativeToolNames: ReadonlySet<string>,
73→): ToolClassification {
74→  if (brainNativeToolNames.has(tool.name)) {
75→    return { kind: "brain_native" };
76→  }
77→
78→  const toolResource = buildToolResource(tool.toolkit, tool.name);
79→  const matchingIntent = findMatchingIntent(toolResource, effectiveScope);
80→
81→  if (matchingIntent) {
82→    return { kind: "authorized", matchingIntent };
83→  }
84→
85→  return { kind: "gated" };
86→}
87→
88→/** Classifies each granted tool as authorized, gated, or brain_native. */
89→export function classifyTools(
90→  grantedTools: readonly ResolvedTool[],
91→  effectiveScope: EffectiveScope,
92→  brainNativeToolNames: ReadonlySet<string>,
93→): readonly ClassifiedTool[] {
94→  return grantedTools.map((tool) => ({
95→    tool,
96→    classification: classifyTool(tool, effectiveScope, brainNativeToolNames),
97→  }));
98→}
99→

  1→/**
  2→ * Agent MCP Route -- Effect boundary for /mcp/agent/:sessionId
  3→ *
  4→ * Handles JSON-RPC requests from sandbox coding agents. Parses the
  5→ * JSON-RPC envelope, resolves auth context, and dispatches to
  6→ * method-specific handlers.
  7→ *
  8→ * Effect boundary: this module performs IO (DB queries, request parsing).
  9→ * Pure logic lives in scope-engine.ts, tools-list-handler.ts, and
 10→ * error-response-builder.ts.
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { ServerDependencies } from "../runtime/types";
 14→import { HttpError } from "../http/errors";
 15→import { jsonResponse } from "../http/response";
 16→import { resolveAgentSession, type AgentSessionContext } from "./agent-mcp-auth";
 17→import {
 18→  computeEffectiveScope,
 19→  classifyTools,
 20→  type AuthorizedIntentSummary,
 21→  type ClassifiedTool,
 22→} from "./scope-engine";
 23→import { buildToolsList, BRAIN_NATIVE_TOOL_NAMES } from "./tools-list-handler";
 24→import { handleToolCall, type ToolCallParams } from "./tools-call-handler";
 25→import { handleCreateIntent } from "./create-intent-handler";
 26→import {
 27→  resolveToolsForIdentity,
 28→  createQueryGrantedTools,
 29→  createToolResolutionCache,
 30→  type ToolResolutionCache,
 31→  type QueryGrantedTools,
 32→} from "../proxy/tool-resolver";
 33→import type { BrainAction } from "../oauth/types";
 34→
 35→// ---------------------------------------------------------------------------
 36→// Types
 37→// ---------------------------------------------------------------------------
 38→
 39→type JsonRpcRequest = {
 40→  readonly jsonrpc: string;
 41→  readonly id: string | number | null;
 42→  readonly method: string;
 43→  readonly params?: Record<string, unknown>;
 44→};
 45→
 46→type JsonRpcResponse = {
 47→  readonly jsonrpc: "2.0";
 48→  readonly id: string | number | null;
 49→  readonly result?: unknown;
 50→  readonly error?: {
 51→    readonly code: number;
 52→    readonly message: string;
 53→    readonly data?: unknown;
 54→  };
 55→};
 56→
 57→type IntentRow = {
 58→  id: RecordId<"intent">;
 59→  authorization_details?: readonly BrainAction[];
 60→};
 61→
 62→// ---------------------------------------------------------------------------
 63→// JSON-RPC helpers (pure)
 64→// ---------------------------------------------------------------------------
 65→
 66→function jsonRpcSuccess(id: string | number | null, result: unknown): JsonRpcResponse {
 67→  return { jsonrpc: "2.0", id, result };
 68→}
 69→
 70→function jsonRpcError(
 71→  id: string | number | null,
 72→  code: number,
 73→  message: string,
 74→  data?: unknown,
 75→): JsonRpcResponse {
 76→  return { jsonrpc: "2.0", id, error: { code, message, ...(data !== undefined ? { data } : {}) } };
 77→}
 78→
 79→// ---------------------------------------------------------------------------
 80→// Query ports (effect boundary)
 81→// ---------------------------------------------------------------------------
 82→
 83→/**
 84→ * Query authorized intents gating a specific agent session.
 85→ * Returns intent summaries with authorization_details for scope computation.
 86→ */
 87→async function querySessionIntents(
 88→  surreal: Surreal,
 89→  sessionId: string,
 90→): Promise<readonly AuthorizedIntentSummary[]> {
 91→  const sessionRecord = new RecordId("agent_session", sessionId);
 92→
 93→  const [rows] = await surreal.query<[IntentRow[]]>(
 94→    `SELECT id, authorization_details
 95→     FROM intent
 96→     WHERE id IN (SELECT VALUE in FROM gates WHERE out = $sess)
 97→       AND status = 'authorized';`,
 98→    { sess: sessionRecord },
 99→  );
100→
101→  return (rows ?? []).map((row) => ({
102→    intentId: row.id.id as string,
103→    authorizationDetails: row.authorization_details ?? [],
104→  }));
105→}
106→
107→// ---------------------------------------------------------------------------
108→// Shared scope computation
109→// ---------------------------------------------------------------------------
110→
111→/**
112→ * Resolve intents, compute scope, and classify tools for a session.
113→ * Shared between tools/list and tools/call handlers.
114→ */
115→async function resolveClassifiedTools(
116→  context: AgentSessionContext,
117→  surreal: Surreal,
118→  queryTools: QueryGrantedTools,
119→  toolCache: ToolResolutionCache,
120→): Promise<readonly ClassifiedTool[]> {
121→  const intents = await querySessionIntents(surreal, context.sessionId);
122→  const effectiveScope = computeEffectiveScope(intents);
123→  const grantedTools = await resolveToolsForIdentity(
124→    context.identityId,
125→    context.workspaceId,
126→    queryTools,
127→    toolCache,
128→  );
129→  return classifyTools(grantedTools, effectiveScope, BRAIN_NATIVE_TOOL_NAMES);
130→}
131→
132→// ---------------------------------------------------------------------------
133→// Method handlers
134→// ---------------------------------------------------------------------------
135→
136→async function handleToolsList(
137→  context: AgentSessionContext,
138→  surreal: Surreal,
139→  queryTools: QueryGrantedTools,
140→  toolCache: ToolResolutionCache,
141→): Promise<unknown> {
142→  const classifiedTools = await resolveClassifiedTools(context, surreal, queryTools, toolCache);
143→  return buildToolsList(classifiedTools);
144→}
