146→// ---------------------------------------------------------------------------
147→// Route Handler Factory
148→// ---------------------------------------------------------------------------
149→
150→export function createAgentMcpHandler(deps: ServerDependencies) {
151→  const queryTools = createQueryGrantedTools(deps.surreal);
152→  const toolCache = createToolResolutionCache(0); // No cache for agent MCP (fresh every request)
153→
154→  return async (sessionId: string, request: Request): Promise<Response> => {
155→    let requestId: string | number | null = null;
156→
157→    try {
158→      // Parse JSON-RPC envelope
159→      const body = (await request.json()) as JsonRpcRequest;
160→      requestId = body.id ?? null;
161→
162→      if (body.jsonrpc !== "2.0" || !body.method) {
163→        return jsonResponse(
164→          jsonRpcError(requestId, -32600, "Invalid Request"),
165→          400,
166→        );
167→      }
168→
169→      // Resolve auth context (throws HttpError on failure)
170→      const context = await resolveAgentSession(request, deps.surreal);
171→
172→      // Verify the URL session ID matches the resolved session
173→      if (context.sessionId !== sessionId) {
174→        throw new HttpError(404, "Session ID mismatch");
175→      }
176→
177→      // Dispatch by method
178→      switch (body.method) {
179→        case "tools/list": {
180→          const result = await handleToolsList(context, deps.surreal, queryTools, toolCache);
181→          return jsonResponse(jsonRpcSuccess(requestId, result), 200);
182→        }
183→
184→        case "tools/call": {
185→          const toolName = (body.params?.name as string) ?? "";
186→          const toolArgs = body.params?.arguments as Record<string, unknown> ?? {};
187→
188→          // Brain-native tools are handled directly, not via classified tool lookup
189→          if (toolName === "create_intent") {
190→            const outcome = await handleCreateIntent(
191→              toolArgs,
192→              {
193→                workspaceId: context.workspaceId,
194→                identityId: context.identityId,
195→                sessionId: context.sessionId,
196→              },
197→              deps.surreal,
198→            );
199→
200→            if (outcome.status === "authorized") {
201→              return jsonResponse(
202→                jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
203→                200,
204→              );
205→            }
206→            if (outcome.status === "pending_veto") {
207→              return jsonResponse(
208→                jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
209→                200,
210→              );
211→            }
212→            if (outcome.status === "vetoed") {
213→              return jsonResponse(
214→                jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId, reason: outcome.reason }),
215→                200,
216→              );
217→            }
218→            return jsonResponse(
219→              jsonRpcError(requestId, -32000, outcome.reason),
220→              500,
221→            );
222→          }
223→
224→          // Non-brain-native tools: classify and dispatch
225→          const classifiedTools = await resolveClassifiedTools(
226→            context, deps.surreal, queryTools, toolCache,
227→          );
228→          const callParams: ToolCallParams = {
229→            name: toolName,
230→            arguments: body.params?.arguments as Record<string, unknown> | undefined,
231→          };
232→          const callResult = await handleToolCall(
233→            callParams,
234→            classifiedTools,
235→            {
236→              workspaceId: context.workspaceId,
237→              identityId: context.identityId,
238→              sessionId: context.sessionId,
239→            },
240→            {
241→              surreal: deps.surreal,
242→              mcpClientFactory: deps.mcpClientFactory,
243→              inflight: deps.inflight,
244→            },
245→          );
246→
247→          if (callResult.kind === "success") {
248→            return jsonResponse(jsonRpcSuccess(requestId, callResult.result), 200);
249→          }
250→          // Error response: use appropriate HTTP status
251→          const httpStatus = callResult.code === -32403 ? 403
252→            : callResult.code === -32602 ? 400
253→            : callResult.code === -32601 ? 501
254→            : 500;
255→          return jsonResponse(
256→            jsonRpcError(requestId, callResult.code, callResult.message, callResult.data),
257→            httpStatus,
258→          );
259→        }
260→
261→        case "create_intent": {
262→          // Also handle create_intent as a top-level JSON-RPC method
263→          const intentArgs = body.params ?? {};
264→          const outcome = await handleCreateIntent(
265→            intentArgs,
266→            {
267→              workspaceId: context.workspaceId,
268→              identityId: context.identityId,
269→              sessionId: context.sessionId,
270→            },
271→            deps.surreal,
272→          );
273→
274→          if (outcome.status === "authorized") {
275→            return jsonResponse(
276→              jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
277→              200,
278→            );
279→          }
280→          if (outcome.status === "pending_veto") {
281→            return jsonResponse(
282→              jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
283→              200,
284→            );
285→          }
286→          if (outcome.status === "vetoed") {
287→            return jsonResponse(
288→              jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId, reason: outcome.reason }),
289→              200,
290→            );
291→          }
292→          return jsonResponse(
293→            jsonRpcError(requestId, -32000, outcome.reason),
294→            500,
295→          );
296→        }
297→
298→        default:
299→          return jsonResponse(
300→            jsonRpcError(requestId, -32601, "Method not found"),
301→            404,
302→          );
303→      }
304→    } catch (error) {
305→      if (error instanceof HttpError) {
306→        return jsonResponse(
307→          jsonRpcError(requestId, -32000, error.message),
308→          error.status,
309→        );
310→      }
311→      throw error;
312→    }
313→  };
314→}
