57→export function createSearchEntitiesTool(deps: ChatToolDeps) {
58→  return tool({
59→    description:
60→      "Full-text search across the knowledge graph. Use for finding entities by keyword or topic (e.g. \"authentication decisions\", \"payment tasks\"). For listing entities by kind or status, use list_workspace_entities instead.",
61→    inputSchema: z.object({
62→      query: z.string().min(1).describe("Search query (keywords matched via BM25 full-text search)"),
63→      kinds: z.array(z.enum(["project", "feature", "task", "decision", "question", "suggestion"]))
64→        .optional()
65→        .describe("Optional filter by entity kinds"),
66→      limit: z.number().int().min(1).max(25).default(10).describe("Maximum number of results"),
67→    }),
68→    execute: async (input, options) => {
69→      const context = requireToolContext(options);
70→      return executeSearchEntities(deps.surreal, context.workspaceRecord, {
71→        query: input.query,
72→        kinds: input.kinds as SearchEntityKind[] | undefined,
73→        limit: input.limit,
74→      });
75→    },
76→  });
77→}
