10→export function createCreateObservationTool(deps: ChatToolDeps) {
11→  return tool({
12→    description:
13→      "Create an observation in the workspace graph. Use proactively when you notice cross-cutting concerns — risks, conflicts, gaps, or notable facts — even if the user didn't ask.",
14→    inputSchema: z.object({
15→      text: z.string().min(1).describe("Observation text"),
16→      severity: z
17→        .enum(["info", "warning", "conflict"])
18→        .describe(
19→          "info: awareness-level signals. warning: risks to address soon. conflict: contradictions needing human resolution.",
20→        ),
21→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional observation category"),
22→      related_entity_id: z
23→        .string()
24→        .optional()
25→        .describe("Optional related entity id (project/feature/task/decision/question)"),
26→    }),
27→    execute: async (input, options) => {
28→      const { context } = await requireAuthorizedContext(options, "create_observation", deps);
29→
30→      const relatedRecord = input.related_entity_id
31→        ? parseRecordIdString(
32→            input.related_entity_id,
33→            ["project", "feature", "task", "decision", "question"],
34→          ) as RecordId<"project" | "feature" | "task" | "decision" | "question", string>
35→        : undefined;
36→
37→      if (relatedRecord) {
38→        const scoped = await isEntityInWorkspace(deps.surreal, context.workspaceRecord, relatedRecord);
39→        if (!scoped) {
40→          throw new Error("related entity is outside the current workspace scope");
41→        }
42→      }
43→
44→      const observationRecord = await createObservation({
45→        surreal: deps.surreal,
46→        workspaceRecord: context.workspaceRecord,
47→        text: input.text,
48→        severity: input.severity,
49→        ...(input.category ? { category: input.category } : {}),
50→        sourceAgent: context.actor,
51→        now: new Date(),
52→        sourceMessageRecord: context.currentMessageRecord,
53→        ...(relatedRecord ? { relatedRecords: [relatedRecord] } : {}),
54→      });
55→
56→      return {
57→        observation_id: `observation:${observationRecord.id as string}`,
58→        severity: input.severity,
59→        status: "open",
60→      };
61→    },
62→  });
63→}
