 19→export function createCreateWorkItemTool(deps: ChatToolDeps) {
 20→  return tool({
 21→    description:
 22→      "Create a task, feature, or project directly in the knowledge graph. Use when the user explicitly requests creation (\"add a task for X\") or during onboarding entity seeding. For uncertain/brainstormed items, prefer suggest_work_items instead.",
 23→    inputSchema: z.object({
 24→      kind: z.enum(["task", "feature", "project"]).describe(
 25→        "project: named product area or workstream (MUST create before features/tasks can belong to it). feature: capability within an existing project. task: concrete executable work with action verb. If no projects exist yet, create a project first.",
 26→      ),
 27→      title: z.string().min(1).describe("Concise entity title"),
 28→      rationale: z.string().min(1).describe("Why this entity is needed — seeds the description"),
 29→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Category classification"),
 30→      priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important, needs attention soon. medium: normal priority. low: nice-to-have, deferred."),
 31→      project: z.string().min(1).optional().describe("Project name to scope the entity under"),
 32→      feature: z.string().min(1).optional().describe("Feature name or record id to scope a task under"),
 33→    }),
 34→    execute: async (input, options) => {
 35→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 36→      const now = new Date();
 37→
 38→      const entityId = randomUUID();
 39→
 40→      // Hard guard: never create a project with the same name as the workspace
 41→      if (input.kind === "project") {
 42→        const [ws] = await deps.surreal.query<[{ name: string } | undefined]>(
 43→          "SELECT name FROM ONLY $ws;",
 44→          { ws: context.workspaceRecord },
 45→        );
 46→        if (ws && input.title.toLowerCase().trim() === ws.name.toLowerCase().trim()) {
 47→          return {
 48→            error: `"${input.title}" is the workspace name, not a project. Create the user's described items (e.g. Dashboard, Inventory) as projects instead.`,
 49→          };
 50→        }
 51→
 52→        const projectRecord = await createProjectRecord({
 53→          surreal: deps.surreal,
 54→          name: input.title,
 55→          status: "active",
 56→          now,
 57→          workspaceRecord: context.workspaceRecord,
 58→          sourceMessageRecord: context.currentMessageRecord,
 59→        });
 60→
 61→        await seedDescriptionEntry({
 62→          surreal: deps.surreal,
 63→          targetRecord: projectRecord,
 64→          text: input.rationale,
 65→        }).catch(() => undefined);
 66→
 67→        await createExtractionProvenanceEdge({
 68→          surreal: deps.surreal,
 69→          sourceRecord: context.currentMessageRecord,
 70→          targetRecord: projectRecord,
 71→          now,
 72→          confidence: 0.95,
 73→          model: deps.extractionModelId,
 74→          fromText: input.title,
 75→          evidence: context.latestUserText,
 76→          evidenceSourceRecord: context.currentMessageRecord,
 77→        });
 78→
 79→        return {
 80→          entity_id: `project:${projectRecord.id as string}`,
 81→          kind: "project" as const,
 82→          title: input.title,
 83→        };
 84→      }
 85→
 86→      if (input.kind === "task") {
 87→        const taskRecord = new RecordId("task", entityId);
 88→        await deps.surreal.create(taskRecord).content({
 89→          title: input.title,
 90→          status: "open",
 91→          workspace: context.workspaceRecord,
 92→          ...(input.category ? { category: input.category } : {}),
 93→          ...(input.priority ? { priority: input.priority } : {}),
 94→          created_at: now,
 95→          updated_at: now,
 96→        });
 97→
 98→        if (input.project) {
 99→          try {
100→            const projectRecord = await resolveWorkspaceProjectRecord({
101→              surreal: deps.surreal,
102→              workspaceRecord: context.workspaceRecord,
103→              projectInput: input.project,
104→            });
105→            await deps.surreal
106→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
107→                added_at: now,
108→              })
109→              .output("after");
110→          } catch (err) {
111→            log.error("create_work_item", `failed to link task to project "${input.project}"`, err);
112→          }
113→        }
114→
115→        if (input.feature) {
116→          try {
117→            const featureRecord = await resolveWorkspaceFeatureRecord({
118→              surreal: deps.surreal,
119→              workspaceRecord: context.workspaceRecord,
120→              featureInput: input.feature,
121→            });
122→
123→            await deps.surreal
124→              .relate(featureRecord, new RecordId("has_task", randomUUID()), taskRecord, {
125→                added_at: now,
126→              })
127→              .output("after");
128→
129→            await deps.surreal
130→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), featureRecord, {
131→                added_at: now,
132→              })
133→              .output("after");
134→          } catch (err) {
135→            log.error("create_work_item", `failed to link task to feature "${input.feature}"`, err);
136→          }
137→        }
138→
139→        await seedDescriptionEntry({
140→          surreal: deps.surreal,
141→          targetRecord: taskRecord,
142→          text: input.rationale,
143→        }).catch(() => undefined);
144→
145→        await createExtractionProvenanceEdge({
146→          surreal: deps.surreal,
147→          sourceRecord: context.currentMessageRecord,
148→          targetRecord: taskRecord,
149→          now,
150→          confidence: 0.95,
151→          model: deps.extractionModelId,
152→          fromText: input.title,
153→          evidence: context.latestUserText,
154→          evidenceSourceRecord: context.currentMessageRecord,
155→        });
156→
157→        return {
158→          entity_id: `task:${entityId}`,
159→          kind: "task" as const,
160→          title: input.title,
161→        };
162→      }
163→
164→      // feature
165→      const featureRecord = new RecordId("feature", entityId);
166→      await deps.surreal.create(featureRecord).content({
167→        name: input.title,
168→        status: "active",
169→        workspace: context.workspaceRecord,
170→        ...(input.category ? { category: input.category } : {}),
171→        created_at: now,
172→        updated_at: now,
173→      });
174→
175→      if (input.project) {
176→        try {
177→          const projectRecord = await resolveWorkspaceProjectRecord({
178→            surreal: deps.surreal,
179→            workspaceRecord: context.workspaceRecord,
180→            projectInput: input.project,
181→          });
182→          await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
183→
184→          await fireDescriptionUpdates({
185→            surreal: deps.surreal,
186→            extractionModel: deps.extractionModel,
187→            trigger: {
188→              kind: "feature_created",
189→              entity: featureRecord,
190→              summary: `Feature added: ${input.title}`,
191→            },
192→          }).catch(() => undefined);
193→        } catch (err) {
194→          log.error("create_work_item", `failed to link feature to project "${input.project}"`, err);
195→        }
196→      }
197→
198→      await seedDescriptionEntry({
199→        surreal: deps.surreal,
200→        targetRecord: featureRecord,
201→        text: input.rationale,
202→      }).catch(() => undefined);
203→
204→      await createExtractionProvenanceEdge({
205→        surreal: deps.surreal,
206→        sourceRecord: context.currentMessageRecord,
207→        targetRecord: featureRecord,
208→        now,
209→        confidence: 0.95,
210→        model: deps.extractionModelId,
211→        fromText: input.title,
212→        evidence: context.latestUserText,
213→        evidenceSourceRecord: context.currentMessageRecord,
214→      });
215→
216→      return {
217→        entity_id: `feature:${entityId}`,
218→        kind: "feature" as const,
219→        title: input.title,
220→      };
221→    },
222→  });
223→}
