18→export function toDecisionRecordId(value: string): RecordId<"decision", string> {
19→  const normalized = value.trim();
20→  if (normalized.length === 0) {
21→    throw new Error("decision id is required");
22→  }
23→
24→  if (normalized.includes(":")) {
25→    const [table, id] = normalized.split(":", 2);
26→    if (table !== "decision" || !id) {
27→      throw new Error("decision id must reference a decision record");
28→    }
29→    return new RecordId("decision", id);
30→  }
31→
32→  return new RecordId("decision", normalized);
33→}
