 84→function normalizeTokens(value: string): Set<string> {
 85→  return new Set(
 86→    value
 87→      .toLowerCase()
 88→      .replace(/[^a-z0-9\s]/g, " ")
 89→      .split(/\s+/)
 90→      .map((t) => t.trim())
 91→      .filter((t) => t.length > 2),
 92→  );
 93→}
 94→
 95→function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
 96→  for (const v of a) {
 97→    if (b.has(v)) return true;
 98→  }
 99→  return false;
100→}

