254→  /** POST /api/mcp/:workspaceId/context — Intent-based context resolution */
255→  async function handleIntentContext(workspaceId: string, request: Request): Promise<Response> {
256→    const auth = await requireAuth(request);
257→    if (auth instanceof Response) return auth;
258→
259→    const body = await parseJsonBody<IntentContextInput>(request);
260→    if (body instanceof Response) return body;
261→
262→    if (!body.intent || typeof body.intent !== "string") {
263→      return jsonError("intent is required", 400);
264→    }
265→
266→    try {
267→      const result = await resolveIntentContext({
268→        surreal,
269→        workspaceRecord: auth.workspaceRecord,
270→        workspaceName: auth.workspaceName,
271→        intent: body.intent,
272→        cwd: body.cwd,
273→        paths: body.paths,
274→      });
275→
276→      // 04-03: Search recent graph changes and classify by similarity
277→      let urgentUpdates: Array<{ entity_id: string; entity_type: string; change_description: string; similarity: number; level: "urgent" | "update" }> = [];
278→      let contextUpdates: Array<{ entity_id: string; entity_type: string; change_description: string; similarity: number; level: "urgent" | "update" }> = [];
279→
280→      try {
281→        // Read last_request_at FIRST, then update — otherwise we search "since now" and find nothing.
282→        let lastRequestAt = new Date(Date.now() - 24 * 60 * 60 * 1000);
283→        if (body.session_id) {
284→          const sessionRecord = new RecordId("agent_session", body.session_id);
285→          const [sessionRows] = await surreal
286→            .query<[Array<{ last_request_at?: string }>]>(
287→              `SELECT last_request_at FROM $sess;`,
288→              { sess: sessionRecord },
289→            )
290→            .collect<[Array<{ last_request_at?: string }>]>();
291→          if (sessionRows[0]?.last_request_at) {
292→            lastRequestAt = new Date(sessionRows[0].last_request_at);
293→          }
294→        }
295→
296→        const searchRecentChanges = createSearchRecentChanges(surreal);
297→        const candidates = await searchRecentChanges(body.intent, workspaceId, lastRequestAt);
298→
299→        // Update agent_session.last_request_at AFTER search (04-02)
300→        if (body.session_id) {
301→          const sessionRecord = new RecordId("agent_session", body.session_id);
302→          deps.inflight.track(
303→            surreal.query(
304→              `UPDATE $sess SET last_request_at = time::now();`,
305→              { sess: sessionRecord },
306→            ).catch(() => undefined),
307→          );
308→        }
309→        const classified = classifyByAge(candidates, new Date());
310→
311→        function toUpdateItem(change: ClassifiedChange) {
312→          return {
313→            entity_id: change.id,
314→            entity_type: change.table,
315→            change_description: change.text,
316→            similarity: change.similarity,
317→            level: (change.classification === "urgent-context" ? "urgent" : "update") as "urgent" | "update",
318→          };
319→        }
320→
321→        urgentUpdates = classified
322→          .filter((c) => c.classification === "urgent-context")
323→          .map(toUpdateItem);
324→        contextUpdates = classified
325→          .filter((c) => c.classification === "context-update")
326→          .map(toUpdateItem);
327→      } catch (error) {
328→        log.warn("mcp.intent-context.recent-changes-failed", "Failed to search recent changes", {
329→          error: error instanceof Error ? error.message : String(error),
330→        });
331→      }
332→
333→      log.info("mcp.intent-context.resolved", "Intent context resolved", {
334→        workspaceId, level: result.level,
335→        urgentCount: urgentUpdates.length, contextCount: contextUpdates.length,
336→      });
337→      return jsonResponse({ ...result, urgent_updates: urgentUpdates, context_updates: contextUpdates }, 200);
338→    } catch (error) {
339→      log.error("mcp.intent-context.failed", "Failed to resolve intent context", error);
340→      return jsonError("failed to resolve intent context", 500);
341→    }
342→  }
