621→  /** POST /api/mcp/:workspaceId/decisions/resolve — Infer decision from graph */
622→  async function handleResolveDecision(_workspaceId: string, request: Request): Promise<Response> {
623→    const auth = await requireAuth(request);
624→    if (auth instanceof Response) return auth;
625→
626→    const perm = await checkAuthority({ surreal, agentType: DEFAULT_AGENT_TYPE, action: "create_decision", workspaceRecord: auth.workspaceRecord });
627→    const denied = checkAuthorityOrError(perm, "create_decision", auth.actorType);
628→    if (denied) return denied;
629→
630→    const body = await parseJsonBody<{
631→      question: string;
632→      options?: string[];
633→      context?: { project?: string; feature?: string };
634→    }>(request);
635→    if (body instanceof Response) return body;
636→    if (!body.question) return jsonError("question is required", 400);
637→
638→    // Search for related decisions via BM25 fulltext
639→    const candidates = await searchEntitiesByBm25({
640→      surreal,
641→      workspaceRecord: auth.workspaceRecord,
642→      query: body.question,
643→      kinds: ["decision"],
644→      limit: 10,
645→    });
646→
647→    // Check if any existing decision resolves the question
648→    const questionTokens = normalizeTokens(body.question);
649→    const relevant = candidates.filter((c) => {
650→      const tokens = normalizeTokens(c.name);
651→      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
652→    });
653→
654→    if (relevant.length > 0) {
655→      const best = relevant[0];
656→      return jsonResponse({
657→        decision: best.name,
658→        confidence: Number(best.score.toFixed(4)),
659→        status: best.status ?? "unknown",
660→        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
661→        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
662→      }, 200);
663→    }
664→
665→    return jsonResponse({
666→      decision: undefined,
667→      confidence: 0,
668→      status: "unresolved",
669→      rationale: "No existing decision found that resolves this question",
670→      sources: candidates.slice(0, 5).map((c) => ({
671→        id: `${c.kind}:${c.id}`,
672→        name: c.name,
673→        score: Number(c.score.toFixed(4)),
674→      })),
675→    }, 200);
676→  }
