 17→export async function executeListWorkspaceEntities(
 18→  surreal: Surreal,
 19→  workspaceRecord: RecordId<"workspace", string>,
 20→  input: { kind: string; status?: string; project?: string; limit: number },
 21→) {
 22→  const projectRecord = input.project
 23→    ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord, projectInput: input.project })
 24→    : undefined;
 25→
 26→  if (input.kind === "project") {
 27→    const projects = await listWorkspaceProjectSummaries({ surreal, workspaceRecord, limit: input.limit });
 28→    return {
 29→      kind: "project",
 30→      count: projects.length,
 31→      entities: projects.map((p) => ({ id: `project:${p.id}`, name: p.name, activeTaskCount: p.activeTaskCount })),
 32→    };
 33→  }
 34→
 35→  if (input.kind === "task") {
 36→    return listTasks(surreal, workspaceRecord, projectRecord, input.status, input.limit);
 37→  }
 38→
 39→  if (input.kind === "feature") {
 40→    return listFeatures(surreal, workspaceRecord, projectRecord, input.status, input.limit);
 41→  }
 42→
 43→  if (input.kind === "decision") {
 44→    const decisions = await listWorkspaceRecentDecisions({ surreal, workspaceRecord, limit: input.limit });
 45→    const filtered = input.status ? decisions.filter((d) => d.status === input.status) : decisions;
 46→    return {
 47→      kind: "decision",
 48→      count: filtered.length,
 49→      entities: filtered.map((d) => ({
 50→        id: `decision:${d.id}`, name: d.name, status: d.status,
 51→        ...(d.priority ? { priority: d.priority } : {}),
 52→        ...(d.project ? { project: d.project } : {}),
 53→      })),
 54→    };
 55→  }
 56→
 57→  if (input.kind === "question") {
 58→    const questions = await listWorkspaceOpenQuestions({ surreal, workspaceRecord, limit: input.limit });
 59→    return {
 60→      kind: "question",
 61→      count: questions.length,
 62→      entities: questions.map((q) => ({
 63→        id: `question:${q.id}`, name: q.name,
 64→        ...(q.priority ? { priority: q.priority } : {}),
 65→        ...(q.project ? { project: q.project } : {}),
 66→      })),
 67→    };
 68→  }
 69→
 70→  if (input.kind === "observation") {
 71→    const observations = await listWorkspaceOpenObservations({ surreal, workspaceRecord, limit: input.limit });
 72→    return {
 73→      kind: "observation",
 74→      count: observations.length,
 75→      entities: observations.map((o) => ({
 76→        id: `observation:${o.id}`, text: o.text, severity: o.severity, status: o.status,
 77→        ...(o.category ? { category: o.category } : {}),
 78→        sourceAgent: o.sourceAgent,
 79→      })),
 80→    };
 81→  }
 82→
 83→  throw new Error(`unsupported entity kind: ${input.kind}`);
 84→}
