108→async function listTasks(
109→  surreal: Surreal,
110→  workspaceRecord: RecordId<"workspace", string>,
111→  projectRecord: RecordId<"project", string> | undefined,
112→  status: string | undefined,
113→  limit: number,
114→) {
115→  const conditions = ["workspace = $workspace"];
116→  const params: Record<string, unknown> = { workspace: workspaceRecord, limit };
117→
118→  if (projectRecord) {
119→    conditions.push(
120→      "(id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)"
121→      + " OR id IN (SELECT VALUE out FROM has_task WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)))",
122→    );
123→    params.project = projectRecord;
124→  }
125→
126→  if (status) {
127→    conditions.push("status = $status");
128→    params.status = status;
129→  }
130→
131→  const query = [
132→    "SELECT id, title, status, priority, created_at",
133→    "FROM task",
134→    `WHERE ${conditions.join(" AND ")}`,
135→    "ORDER BY created_at DESC",
136→    "LIMIT $limit;",
137→  ].join(" ");
138→
139→  const [rows] = await surreal
140→    .query<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>(query, params)
141→    .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>();
142→
143→  return {
144→    kind: "task",
145→    count: rows.length,
146→    entities: rows.map((t) => ({
147→      id: `task:${(t.id.id as string)}`,
148→      name: t.title,
149→      status: t.status,
150→      ...(t.priority ? { priority: t.priority } : {}),
151→    })),
152→  };
153→}
