  1→/**
  2→ * Agent MCP Auth — Resolve proxy token to agent session context
  3→ *
  4→ * Effect boundary module: extracts X-Brain-Auth header, resolves proxy token
  5→ * via existing lookupProxyToken, loads agent_session record, and returns
  6→ * AgentSessionContext.
  7→ *
  8→ * Pipeline:
  9→ *   1. Extract X-Brain-Auth header (raw token, no "Bearer " prefix)
 10→ *   2. Hash token and look up via createLookupProxyToken
 11→ *   3. Verify session field exists on proxy token
 12→ *   4. Load agent_session record from SurrealDB
 13→ *   5. Check orchestrator_status is 'active' or 'idle'
 14→ *   6. Return AgentSessionContext
 15→ */
 16→import { RecordId, type Surreal } from "surrealdb";
 17→import { HttpError } from "../http/errors";
 18→import {
 19→  extractBrainAuthToken,
 20→  createLookupProxyToken,
 21→} from "../proxy/proxy-auth";
 22→import { hashProxyToken } from "../proxy/proxy-token-core";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type AgentSessionContext = {
 29→  readonly workspaceId: string;
 30→  readonly identityId: string;
 31→  readonly sessionId: string;
 32→  readonly sessionRecord: RecordId<"agent_session">;
 33→  readonly workspaceRecord: RecordId<"workspace">;
 34→  readonly identityRecord: RecordId<"identity">;
 35→};
 36→
 37→type AgentSessionRow = {
 38→  id: RecordId<"agent_session">;
 39→  workspace: RecordId<"workspace">;
 40→  orchestrator_status: string;
 41→};
 42→
 43→const ALLOWED_SESSION_STATUSES = new Set(["active", "idle"]);
 44→
 45→// ---------------------------------------------------------------------------
 46→// resolveAgentSession
 47→// ---------------------------------------------------------------------------
 48→
 49→/**
 50→ * Resolve a proxy token from X-Brain-Auth header to an AgentSessionContext.
 51→ *
 52→ * @throws HttpError(401) - invalid, expired, or revoked proxy token
 53→ * @throws HttpError(404) - proxy token has no session, or session not found
 54→ * @throws HttpError(403) - session not in active/idle status
 55→ */
 56→export async function resolveAgentSession(
 57→  request: Request,
 58→  surreal: Surreal,
 59→): Promise<AgentSessionContext> {
 60→  // Step 1: Extract token from header
 61→  const rawToken = extractBrainAuthToken(request.headers);
 62→  if (!rawToken) {
 63→    throw new HttpError(401, "Missing X-Brain-Auth header");
 64→  }
 65→
 66→  // Step 2: Look up proxy token
 67→  const lookupToken = createLookupProxyToken(surreal);
 68→  const tokenHash = hashProxyToken(rawToken);
 69→  const tokenRecord = await lookupToken(tokenHash);
 70→
 71→  if (!tokenRecord) {
 72→    throw new HttpError(401, "Invalid proxy token");
 73→  }
 74→
 75→  if (tokenRecord.revoked) {
 76→    throw new HttpError(401, "Proxy token has been revoked");
 77→  }
 78→
 79→  if (tokenRecord.expiresAt.getTime() <= Date.now()) {
 80→    throw new HttpError(401, "Proxy token has expired");
 81→  }
 82→
 83→  // Step 3: Check session field on proxy token
 84→  if (!tokenRecord.sessionId) {
 85→    throw new HttpError(404, "Proxy token has no linked session");
 86→  }
 87→
 88→  // Step 4: Load agent_session record
 89→  const sessionRecord = new RecordId("agent_session", tokenRecord.sessionId);
 90→  const [rows] = await surreal.query<[AgentSessionRow[]]>(
 91→    `SELECT id, workspace, orchestrator_status FROM $sess;`,
 92→    { sess: sessionRecord },
 93→  );
 94→
 95→  const sessionRow = rows?.[0];
 96→  if (!sessionRow) {
 97→    throw new HttpError(404, "Agent session not found");
 98→  }
 99→
100→  // Step 5: Check orchestrator_status
101→  if (!ALLOWED_SESSION_STATUSES.has(sessionRow.orchestrator_status)) {
102→    throw new HttpError(
103→      403,
104→      `Session status '${sessionRow.orchestrator_status}' is not allowed; must be active or idle`,
105→    );
106→  }
107→
108→  // Step 6: Return context
109→  const workspaceRecord = new RecordId("workspace", tokenRecord.workspaceId);
110→  const identityRecord = new RecordId("identity", tokenRecord.identityId);
111→
112→  return {
113→    workspaceId: tokenRecord.workspaceId,
114→    identityId: tokenRecord.identityId,
115→    sessionId: tokenRecord.sessionId,
116→    sessionRecord,
117→    workspaceRecord,
118→    identityRecord,
119→  };
120→}
