 25→export function createMoveItemsToProjectTool(deps: ChatToolDeps) {
 26→  return tool({
 27→    description:
 28→      "Move existing features or tasks to a different project. Use when reorganizing — e.g. user says items belong under a different project. Deletes the old project edge and creates a new one. Does NOT duplicate entities.",
 29→    inputSchema: z.object({
 30→      entity_ids: z
 31→        .array(z.string().min(1))
 32→        .min(1)
 33→        .describe("Polymorphic entity IDs to move, e.g. ['feature:uuid', 'task:uuid']"),
 34→      target_project: z
 35→        .string()
 36→        .min(1)
 37→        .describe("Target project name or 'project:uuid' to move entities into"),
 38→    }),
 39→    execute: async (input, options) => {
 40→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 41→      const now = new Date();
 42→
 43→      let projectRecord: RecordId<"project", string>;
 44→      try {
 45→        projectRecord = await resolveWorkspaceProjectRecord({
 46→          surreal: deps.surreal,
 47→          workspaceRecord: context.workspaceRecord,
 48→          projectInput: input.target_project,
 49→        });
 50→      } catch (err) {
 51→        return {
 52→          error: `Target project not found: ${input.target_project}`,
 53→          moved: [],
 54→          failed: input.entity_ids.map((id) => ({ entity_id: id, reason: "target project resolution failed" })),
 55→        };
 56→      }
 57→
 58→      const moved: MoveResult[] = [];
 59→      const failed: MoveFailure[] = [];
 60→
 61→      for (const rawId of input.entity_ids) {
 62→        try {
 63→          const entityRecord = parseRecordIdString(rawId, ["feature", "task"]);
 64→          const table = entityRecord.table.name;
 65→
 66→          const inWorkspace = await isEntityInWorkspace(
 67→            deps.surreal,
 68→            context.workspaceRecord,
 69→            entityRecord,
 70→          );
 71→          if (!inWorkspace) {
 72→            failed.push({ entity_id: rawId, reason: "entity not found in workspace" });
 73→            continue;
 74→          }
 75→
 76→          const title = await readEntityName(deps.surreal, entityRecord) ?? rawId;
 77→
 78→          if (table === "feature") {
 79→            // Delete old has_feature edges (project → feature)
 80→            await deps.surreal.query(
 81→              "DELETE FROM has_feature WHERE out = $feature;",
 82→              { feature: entityRecord },
 83→            );
 84→
 85→            // Create new has_feature edge to target project
 86→            await ensureProjectFeatureEdge(
 87→              deps.surreal,
 88→              projectRecord,
 89→              entityRecord as RecordId<"feature", string>,
 90→              now,
 91→            );
 92→
 93→            moved.push({ entity_id: rawId, title });
 94→          } else if (table === "task") {
 95→            // Delete old belongs_to edges to projects only (preserve feature edges)
 96→            await deps.surreal.query(
 97→              "DELETE FROM belongs_to WHERE `in` = $task AND record::tb(out) = 'project';",
 98→              { task: entityRecord },
 99→            );
100→
101→            // Create new belongs_to edge to target project
102→            await deps.surreal
103→              .relate(
104→                entityRecord,
105→                new RecordId("belongs_to", randomUUID()),
106→                projectRecord,
107→                { added_at: now },
108→              )
109→              .output("after");
110→
111→            moved.push({ entity_id: rawId, title });
112→          } else {
113→            failed.push({ entity_id: rawId, reason: `unsupported entity type: ${table}` });
114→          }
115→        } catch (err) {
116→          failed.push({
117→            entity_id: rawId,
118→            reason: err instanceof Error ? err.message : "unknown error",
119→          });
120→        }
121→      }
122→
123→      return { moved, failed };
124→    },
125→  });
126→}
