 52→    conversationId: row.conversation.id as string,
 53→    text: row.text,
 54→    score: row.score,
 55→  }));
 56→
 57→  const enrichedMessages = await Promise.all(
 58→    messages.map(async (message) => {
 59→      const messageRecord = parseRecordIdString(message.id, ["message"], "message");
 60→      const [entityRows] = await surreal
 61→        .query<[Array<GraphEntityRecord>]>(
 62→          "SELECT VALUE out FROM extraction_relation WHERE `in` = $message LIMIT 8;",
 63→          { message: messageRecord },
 64→        )
 65→        .collect<[Array<GraphEntityRecord>]>();
 66→
 67→      const linkedEntities = await Promise.all(
