 97→        conversationId: `conversation:${message.conversationId}`,
 98→        excerpt: message.text.slice(0, 280),
 99→        confidence: Number(message.score.toFixed(4)),
100→        linkedEntities: linkedEntities.filter((value) => value !== undefined),
101→      };
102→    }),
