  changeType: "created" | "modified" | "deleted";
};

export type AgentStatusEvent = {
  type: "agent_status";
  sessionId: string;
  status: "active" | "idle" | "completed" | "aborted" | "error";
  error?: string;
};

export type AgentStallWarningEvent = {
  type: "agent_stall_warning";
  sessionId: string;
  lastEventAt: string;
  stallDurationSeconds: number;
};

export type AgentPromptEvent = {
  type: "agent_prompt";
  sessionId: string;
  text: string;
};

export type AgentPermissionRequestEvent = {
  type: "agent_permission_request";
  sessionId: string;
  permissionId: string;
  toolName: string;
  arguments: string;
  timeoutSeconds: number;
};

export type AgentPermissionResponseEvent = {
  type: "agent_permission_response";
  sessionId: string;
