};

export type AgentRestorationEvent = {
  type: "agent_restoration";
  sessionId: string;
  status: "started" | "completed" | "failed";
  eventsReplayed?: number;
  totalEvents?: number;
};

export type StreamEvent =
  | TokenEvent
  | ReasoningEvent
  | AssistantMessageEvent
  | ExtractionEvent
  | OnboardingSeedEvent
  | OnboardingStateEvent
  | ObservationEvent
  | DoneEvent
  | ErrorEvent
  | AgentTokenEvent
  | AgentFileChangeEvent
  | AgentStatusEvent
  | AgentStallWarningEvent
  | AgentPromptEvent
  | AgentPermissionRequestEvent
  | AgentPermissionResponseEvent
  | AgentRestorationEvent;

export type SearchEntityResponse = {
  id: string;
  kind: EntityKind;
  text: string;
  confidence: number;
  sourceId: string;
  sourceKind: SourceKind;
};

// --- Graph view types ---

export type ReagraphNode = {
  id: string;
  label: string;
  fill: string;
  data: {
    kind: EntityKind;
    connectionCount: number;
    status?: string;
  };
};

export type ReagraphEdge = {
  id: string;
  source: string;
  target: string;
  label: string;
  data: {
    type: string;
    confidence: number;
  };
};

export type GraphResponse = {
